import type { SkillLesson } from "./skill-lesson-types";

// AUTO-GENERATED by scripts/build-skill-lessons.mts. Do not edit by hand.
export const SKILL_LESSONS: SkillLesson[] = [
  {"section":"READING","topic":"key-ideas-details","skill":"Identify the Topic, Main Idea, and Supporting Details","slug":"identify-the-topic-main-idea-and-supporting-details","summary":"Tell apart the broad subject, the central point being made, and the facts that back it up.","blocks":[{"heading":"What it is","body":"Three layers of a text:\n\n- Topic: the general subject in a word or short phrase (\"hand hygiene\").\n- Main idea: the one sentence the author most wants you to take away (often the claim).\n- Supporting details: examples, reasons, and facts that prove the main idea."},{"heading":"How the TEAS tests it","body":"Questions ask \"Which is the topic?\", \"What is the main idea?\", or \"Which detail supports the main idea?\" Wrong answers are usually too narrow (a single detail) or too broad (a topic stated as if it were the point)."},{"heading":"Example","body":"Passage: \"Washing hands for 20 seconds removes more germs than a quick rinse. Studies show longer scrubbing cuts infection rates in clinics.\"\n\n- Topic: handwashing.\n- Main idea: washing for a full 20 seconds removes more germs.\n- Supporting detail: studies show lower infection rates with longer scrubbing."},{"heading":"Tip","body":"Ask \"What is the author trying to convince me of?\" That answer is the main idea. Anything that answers \"How do they prove it?\" is a detail."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Summarize a Multi-Paragraph Text","slug":"summarize-a-multi-paragraph-text","summary":"Capture the central point of a longer passage in a short, accurate restatement without adding opinions.","blocks":[{"heading":"What it is","body":"A summary states the main idea plus the most important supporting points across all paragraphs, in your own condensed words. It leaves out minor examples, repetition, and personal reactions."},{"heading":"How the TEAS tests it","body":"You pick the answer that best summarizes the whole passage. Traps include choices that are true but cover only one paragraph, or that add an idea the text never stated."},{"heading":"Example","body":"A passage describes how a nurse checks a patient's chart, confirms allergies, then verifies the medication label before giving a dose.\n\nBest summary: \"Nurses follow several checks before giving medication to keep patients safe.\"\n\nToo narrow: \"Nurses confirm allergies.\" (only one step)"},{"heading":"Tip","body":"A good summary is shorter than the original and would still make sense to someone who never read it. If a choice mentions a detail from just one paragraph, it is too small."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Infer Logical Conclusions From a Text","slug":"infer-logical-conclusions-from-a-text","summary":"Draw a conclusion the text strongly implies but does not state outright, using only the given evidence.","blocks":[{"heading":"What it is","body":"An inference is a reasonable, evidence-based conclusion that goes one small step beyond what is written. It must be supported by the passage, not by your outside knowledge or guesses."},{"heading":"How the TEAS tests it","body":"Look for stems like \"It can be concluded that...\", \"The passage suggests...\", or \"The reader can infer...\". The right answer is supported by clues in the text; wrong answers overreach or contradict it."},{"heading":"Example","body":"Text: \"By the third night shift, Maria set two alarms and still struggled to wake on time.\"\n\nValid inference: Maria was very tired from the schedule.\n\nNot valid: Maria dislikes her job. (the text never indicates this)"},{"heading":"Tip","body":"Test each choice with \"Can I point to a line that backs this up?\" If you cannot, it is a guess, not an inference. Stay close to the text."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Demonstrate Comprehension of Written Directions","slug":"demonstrate-comprehension-of-written-directions","summary":"Read step-by-step instructions and correctly understand the order, conditions, and required actions.","blocks":[{"heading":"What it is","body":"Following written directions means tracking what to do, in what order, and under what conditions. Words like \"before\", \"after\", \"if\", \"unless\", and \"only\" change the meaning of a step."},{"heading":"How the TEAS tests it","body":"You read a procedure (a recipe, a medication guide, a form) and answer what to do at a certain point or what happens if a condition is met. Misreading a single signal word leads to the wrong answer."},{"heading":"Example","body":"Directions: \"Take one tablet with food. If nausea occurs, stop and call the clinic before the next dose.\"\n\nQuestion: A patient feels nauseated. What should they do? Answer: Stop and call the clinic before taking the next dose."},{"heading":"Tip","body":"Underline conditional words (if, unless, when) and sequence words (first, then, after). Reread the exact step the question points to instead of relying on memory."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Locate Specific Information in a Text","slug":"locate-specific-information-in-a-text","summary":"Scan a passage to find an exact fact, name, number, or detail quickly and accurately.","blocks":[{"heading":"What it is","body":"This is targeted searching, not deep reading. You hunt for one precise piece of information that is stated directly in the text, such as a date, a dosage, a definition, or a location."},{"heading":"How the TEAS tests it","body":"Stems ask \"According to the passage...\" or \"Which detail is stated about...\". The answer is found word-for-word or closely paraphrased in the text, so going back to verify always beats guessing."},{"heading":"Example","body":"Passage: \"The clinic opens at 7 a.m. on weekdays and 9 a.m. on Saturdays.\"\n\nQuestion: When does the clinic open on Saturday? Scan for \"Saturday\" and read the nearby number: 9 a.m."},{"heading":"Tip","body":"Pull a keyword from the question and scan for it in the passage. When you find it, read the full sentence around it so you grab the correct detail, not a similar nearby one."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Identify Information From a Printed Communication","slug":"identify-information-from-a-printed-communication","summary":"Pull accurate facts from everyday documents like memos, emails, letters, labels, and notices.","blocks":[{"heading":"What it is","body":"Printed communications are real-world texts with a purpose: a memo, an email, a flyer, an appointment letter, or a product label. You read for who sent it, who it is for, what it asks, and key dates or details."},{"heading":"How the TEAS tests it","body":"You answer questions about the purpose, audience, action requested, or a specific detail. Pay attention to headings, the subject line, dates, and bolded or highlighted text that organize the information."},{"heading":"Example","body":"A staff email reads: \"Subject: Flu shots. All clinical staff must complete vaccination by November 15. Sign up at the front desk.\"\n\nQuestion: What action is required? Answer: Get a flu shot (sign up at the front desk) by November 15."},{"heading":"Tip","body":"Read the subject line and any header first. They usually tell you the purpose, which makes locating the requested action or deadline much faster."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Identify Information From a Graphic","slug":"identify-information-from-a-graphic","summary":"Read and interpret charts, tables, graphs, diagrams, and labels to find requested data.","blocks":[{"heading":"What it is","body":"Graphics present information visually: tables, bar and line graphs, pie charts, diagrams, and keys. Reading them means using titles, axis labels, units, and legends to locate a value or compare items."},{"heading":"How the TEAS tests it","body":"Questions ask you to read off a value, compare two categories, find a trend, or identify the largest or smallest amount. Misreading axis units or the legend is the most common mistake."},{"heading":"Example","body":"A bar graph shows daily water intake: Monday 6 cups, Tuesday 8, Wednesday 5.\n\nQuestion: Which day had the most water? Find the tallest bar: Tuesday, at 8 cups."},{"heading":"Tip","body":"Before reading values, read the title, both axis labels, and the legend so you know exactly what each number means and what unit it is in."}]},
  {"section":"READING","topic":"key-ideas-details","skill":"Interpret Events in a Sequence","slug":"interpret-events-in-a-sequence","summary":"Determine the correct order of events or steps using time and sequence clues in a text.","blocks":[{"heading":"What it is","body":"Sequencing means putting events or steps in the order they happen. Signal words such as first, next, then, before, after, finally, and dates or times tell you the order even when events are not listed in line."},{"heading":"How the TEAS tests it","body":"You may be asked what happened first or last, what comes right before or after a given step, or to arrange events in order. Watch for clues that an event is described out of order (\"before that, she had...\")."},{"heading":"Example","body":"Text: \"She charted the vitals, but only after she had washed her hands and greeted the patient.\"\n\nOrder: 1) washed hands, 2) greeted the patient, 3) charted vitals. The word \"after\" signals charting came last."},{"heading":"Tip","body":"Do not assume the order of sentences equals the order of events. Trust the signal words like before and after to rebuild the true timeline."}]},
  {"section":"READING","topic":"craft-structure","skill":"Distinguish Between Fact and Opinion","slug":"distinguish-between-fact-and-opinion","summary":"A fact can be proven or checked, while an opinion expresses a belief, judgment, or feeling.","blocks":[{"heading":"What it is","body":"A fact is a statement that can be verified with evidence, measurement, or a reliable source. An opinion states what someone thinks, feels, or values and cannot be proven true for everyone."},{"heading":"How the TEAS tests it","body":"You will be given several sentences and asked which one is a fact or which one is an opinion. Sometimes one passage mixes both and you must label a specific sentence."},{"heading":"Example","body":"Fact: The night shift at the clinic runs from 7 p.m. to 7 a.m.\n\nOpinion: The night shift is the hardest shift to work."},{"heading":"Tip","body":"Watch for opinion signal words: best, worst, should, beautiful, easy, terrible, probably. Facts often include numbers, dates, or things you could look up."}]},
  {"section":"READING","topic":"craft-structure","skill":"Identify Biases and Stereotypes","slug":"identify-biases-and-stereotypes","summary":"Bias is a one-sided slant toward or against something, and a stereotype is an unfair fixed idea about a whole group.","blocks":[{"heading":"What it is","body":"Bias is when an author favors one side and ignores or downplays the other. A stereotype assumes every member of a group shares the same trait, which is rarely true."},{"heading":"How the TEAS tests it","body":"Questions ask you to spot a biased statement, name the author's slant, or identify a sentence that relies on a stereotype rather than evidence."},{"heading":"Example","body":"Biased: Only careless drivers ever get into accidents on this road.\n\nStereotype: Older patients can never learn to use new technology."},{"heading":"Tip","body":"Look for sweeping words like all, none, always, never, or every. These often signal a stereotype or an unbalanced claim."}]},
  {"section":"READING","topic":"craft-structure","skill":"Interpret the Meaning of Words and Phrases Using Context","slug":"interpret-the-meaning-of-words-and-phrases-using-context","summary":"Context clues are the surrounding words that help you figure out what an unfamiliar word or phrase means.","blocks":[{"heading":"What it is","body":"When you do not know a word, the nearby sentences often define it, give an example, restate it, or show a contrast that points to its meaning."},{"heading":"How the TEAS tests it","body":"A word is underlined or quoted, and you choose the answer closest in meaning based only on how it is used in that passage, not a definition you memorized."},{"heading":"Example","body":"The wound began to suppurate, oozing pus and fluid for days.\n\nThe nearby words oozing pus tell you suppurate means to form or discharge pus."},{"heading":"Tip","body":"Cover the word and read the sentence with a blank. Predict a simple word that fits, then pick the answer choice closest to your prediction."}]},
  {"section":"READING","topic":"craft-structure","skill":"Use Dictionary and Library Entries","slug":"use-dictionary-and-library-entries","summary":"Dictionary and reference entries are organized in set parts you read to find meaning, pronunciation, part of speech, and sources.","blocks":[{"heading":"What it is","body":"A dictionary entry lists the word, its pronunciation, part of speech, numbered meanings, and sometimes its origin. Library and catalog entries list title, author, call number, and publication details so you can locate a source."},{"heading":"How the TEAS tests it","body":"You read a sample entry and answer questions such as which numbered meaning fits a sentence, what part of speech a word is, or which call number to use to find a book."},{"heading":"Example","body":"chart (n.) 1. a sheet of information in table form 2. a patient's medical record\n\nIn She updated his chart after rounds, meaning 2 fits."},{"heading":"Tip","body":"Match the part of speech first. If the word is acting as a noun in the sentence, only consider the noun meanings in the entry."}]},
  {"section":"READING","topic":"craft-structure","skill":"Evaluate the Author's Purpose in a Given Text","slug":"evaluate-the-author-s-purpose-in-a-given-text","summary":"The author's purpose is the main reason a text was written: usually to inform, persuade, or entertain.","blocks":[{"heading":"What it is","body":"Every text has a goal. Informational writing explains or teaches, persuasive writing tries to change your mind or get you to act, and entertaining writing tells a story or amuses the reader."},{"heading":"How the TEAS tests it","body":"You read a short passage and choose why the author wrote it. Answer choices often pair a verb with the topic, such as to inform readers about hand washing."},{"heading":"Example","body":"A flyer that says Protect your family now, get the flu shot today is written to persuade, while a chart listing flu symptoms is written to inform."},{"heading":"Tip","body":"Ask what the author wants you to do after reading. If the answer is to believe or to act, the purpose is to persuade."}]},
  {"section":"READING","topic":"craft-structure","skill":"Recognize Text Structure","slug":"recognize-text-structure","summary":"Text structure is the pattern an author uses to organize ideas, such as sequence, cause and effect, compare and contrast, or problem and solution.","blocks":[{"heading":"What it is","body":"Authors arrange information in predictable patterns. Common ones are chronological or sequence order, cause and effect, compare and contrast, problem and solution, and description."},{"heading":"How the TEAS tests it","body":"You identify which structure a paragraph uses, or you use the structure to find a detail, such as what happened next or what caused a result."},{"heading":"Example","body":"First clean the site, then apply the bandage, and finally label the dressing with the date.\n\nThe words first, then, and finally signal a sequence structure."},{"heading":"Tip","body":"Use signal words to spot the pattern: because and as a result point to cause and effect, while however and unlike point to compare and contrast."}]},
  {"section":"READING","topic":"craft-structure","skill":"Analyze Types of Writing","slug":"analyze-types-of-writing","summary":"The four main types of writing are narrative, expository, persuasive, and descriptive, each with its own goal and features.","blocks":[{"heading":"What it is","body":"Narrative writing tells a story with events and characters. Expository writing explains facts and ideas. Persuasive writing argues a position. Descriptive writing paints a detailed picture using the senses."},{"heading":"How the TEAS tests it","body":"You read a passage and name its type, or you match a type to its key features such as a thesis and reasons for persuasive, or sensory detail for descriptive."},{"heading":"Example","body":"A passage describing the sharp smell of antiseptic and the cold metal of the table is descriptive, while one walking through the steps of an injury is narrative."},{"heading":"Tip","body":"Do not confuse type with purpose. Persuasive writing always aims to convince, while expository simply explains without taking a side."}]},
  {"section":"READING","topic":"craft-structure","skill":"Evaluate the Author's Point of View or Perspective in a Given Text","slug":"evaluate-the-author-s-point-of-view-or-perspective-in-a-given-text","summary":"Point of view is the position or attitude an author takes toward the subject, shaped by their perspective and word choice.","blocks":[{"heading":"What it is","body":"An author's point of view is how they see and feel about a topic. It shows through the details they include, the tone they use, and whether they sound for, against, or neutral."},{"heading":"How the TEAS tests it","body":"You determine whether the author supports, opposes, or stays neutral on a subject, or you identify the attitude their wording reveals."},{"heading":"Example","body":"An author who writes that the new visiting hours finally give families the time they deserve reveals a supportive point of view through the words finally and deserve."},{"heading":"Tip","body":"Focus on loaded or emotional word choices. Positive or negative wording usually reveals where the author stands even when they do not say it directly."}]},
  {"section":"READING","topic":"integration-knowledge","skill":"Use Evidence From the Text to Make Predictions, Inferences, and Draw Conclusions","slug":"use-evidence-from-the-text-to-make-predictions-inferences-and-draw-conclusions","summary":"Combine stated clues in a passage with reasoning to figure out what is implied or likely to happen next.","blocks":[{"heading":"What it is","body":"An inference is a logical conclusion the text supports but does not say outright. A prediction is a reasonable guess about what comes next. Both must rest on actual textual evidence, not personal opinion."},{"heading":"How the TEAS tests it","body":"Questions use phrasing like 'the passage suggests,' 'the reader can conclude,' or 'what will most likely happen.' The correct answer stays close to the clues given.\n\n- Wrong choices add information not in the text.\n- Wrong choices overstate or contradict the evidence."},{"heading":"Example","body":"A passage says a nurse double-checked the medication chart twice and asked a coworker to confirm the dose. You can infer the nurse is careful about patient safety, even though the text never uses the word 'careful.'"},{"heading":"Tip","body":"Before picking an answer, point to the exact sentence that backs it up. If you cannot, the choice is probably a trap."}]},
  {"section":"READING","topic":"integration-knowledge","skill":"Compare and Contrast the Themes Expressed in One or More Texts","slug":"compare-and-contrast-the-themes-expressed-in-one-or-more-texts","summary":"Identify the central messages of passages and judge how those messages are alike and different.","blocks":[{"heading":"What it is","body":"A theme is the broad idea or lesson a text conveys, such as resilience or the cost of ambition. Comparing themes means spotting where two texts share a message; contrasting means noting where they differ."},{"heading":"How the TEAS tests it","body":"You may see one passage or two short ones. Questions ask which statement captures a shared theme, or how the texts treat the same idea differently.\n\n- Theme is general, not a plot summary.\n- One author may be hopeful while another is cautious about the same subject."},{"heading":"Example","body":"One short text describes a runner finishing a race despite an injury; another describes a student retaking an exam after failing. Both share the theme of perseverance, but the first stresses physical endurance and the second stresses academic determination."},{"heading":"Tip","body":"Ask 'What big idea is each author getting at?' first, then line the two ideas up side by side to see the overlap and the gap."}]},
  {"section":"READING","topic":"integration-knowledge","skill":"Evaluate an Argument","slug":"evaluate-an-argument","summary":"Judge whether a writer's claim is well supported by reasons and evidence and free of weak reasoning.","blocks":[{"heading":"What it is","body":"An argument has a claim (the main point), supporting reasons, and evidence. Evaluating it means deciding if the support is relevant, sufficient, and logical, or whether it relies on opinion or faulty thinking."},{"heading":"How the TEAS tests it","body":"Questions ask which evidence best supports a claim, which choice weakens the argument, or whether a statement is fact or opinion.\n\n- Strong support is specific and on topic.\n- Watch for emotional language standing in for proof."},{"heading":"Example","body":"A writer claims a clinic should extend evening hours and backs it with a survey showing most patients work daytime jobs. That evidence is relevant. A line saying 'everyone knows mornings are inconvenient' is opinion, not support."},{"heading":"Tip","body":"Separate the claim from its backing, then ask whether the backing would convince a skeptical reader who shares no opinions with the author."}]},
  {"section":"READING","topic":"integration-knowledge","skill":"Identify Primary Sources","slug":"identify-primary-sources","summary":"Recognize firsthand, original records of an event versus secondhand accounts that interpret them.","blocks":[{"heading":"What it is","body":"A primary source is created by someone with direct experience of an event or topic, at the time it happened. A secondary source analyzes, summarizes, or comments on primary material after the fact."},{"heading":"How the TEAS tests it","body":"You are given a list of items or descriptions and asked which is a primary source.\n\n- Primary: diaries, letters, interviews, original research data, photographs, eyewitness reports, lab notes.\n- Secondary: textbooks, review articles, biographies, news analysis of past events."},{"heading":"Example","body":"A patient's own handwritten journal describing recovery is a primary source. A magazine article that summarizes several such journals to describe recovery trends is a secondary source."},{"heading":"Tip","body":"Ask 'Was this made by someone who was actually there at the time?' If yes, it is primary; if it reports on someone else's experience, it is secondary."}]},
  {"section":"READING","topic":"integration-knowledge","skill":"Evaluate and Integrate Data From Multiple Sources Across Various Formats","slug":"evaluate-and-integrate-data-from-multiple-sources-across-various-formats","summary":"Pull information from text, tables, graphs, and labels together to answer a question no single source fully covers.","blocks":[{"heading":"What it is","body":"Integrating data means reading more than one format at once, such as a paragraph plus a chart or a recipe plus a nutrition label, and combining the matching details to reach a conclusion."},{"heading":"How the TEAS tests it","body":"A question gives two or more sources and asks for a fact found by linking them, or which conclusion all the sources support.\n\n- Match labels, units, and headings carefully across formats.\n- The answer often sits in the overlap, not in one source alone."},{"heading":"Example","body":"A paragraph states a medication is dosed by weight, and a table lists doses for each weight range. To find the right dose you read the patient's weight from the text, then locate the matching row in the table."},{"heading":"Tip","body":"Identify what each source contributes before answering, then connect the shared data point that ties them together rather than trusting one in isolation."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Perform Arithmetic Operations with Rational Numbers (Whole Numbers, Decimals, & Fractions)","slug":"perform-arithmetic-operations-with-rational-numbers-whole-numbers-decimals-fractions","summary":"Master order of operations and the four operations across whole numbers, decimals, and fractions, including mixed numbers.","blocks":[{"heading":"Order of Operations (PEMDAS)","body":"Work in this order: Parentheses, Exponents, Multiplication and Division (left to right), Addition and Subtraction (left to right). Multiply and divide rank equally, as do add and subtract, so go left to right within each pair.\n\nExample: 6 + 2 × (3² − 1) ÷ 4\n- Parentheses first, exponent inside: 3² = 9, then 9 − 1 = 8\n- Now: 6 + 2 × 8 ÷ 4\n- Multiply and divide left to right: 2 × 8 = 16, then 16 ÷ 4 = 4\n- Add: 6 + 4 = 10\n\nTip: A common mistake is adding before multiplying. Finish all × and ÷ before any + or −."},{"heading":"Even & Odd Rules","body":"Even numbers end in 0, 2, 4, 6, 8; odd numbers end in 1, 3, 5, 7, 9.\n\n- even + even = even, odd + odd = even, even + odd = odd\n- even × even = even, even × odd = even, odd × odd = odd\n\nIn short, a product is odd only when every factor is odd; if even one factor is even, the product is even.\n\nExample: Is 7 × 14 even or odd? One factor (14) is even, so the product is even. Check: 7 × 14 = 98, which ends in 8, so even."},{"heading":"Whole Number Word Problems","body":"Read the problem, decide the operation, then compute. Total or altogether means add; how many left means subtract; groups of or each suggests multiply; split evenly suggests divide.\n\nExample: A nurse stocks 8 carts with 24 syringes each, then uses 35 from the supply. How many syringes were placed? 8 × 24 = 192 placed (the 35 used is extra information not asked for).\n\nExample: 6 boxes hold 144 gloves total, split evenly. Each box has 144 ÷ 6 = 24 gloves."},{"heading":"Adding & Subtracting Decimals","body":"Line up the decimal points (fill empty places with zeros), then add or subtract as usual, bringing the decimal point straight down.\n\nExample (add): 12.4 + 3.75. Write 12.40 + 3.75. Lined up: 12.40 + 3.75 = 16.15.\n\nExample (subtract): 20.00 − 7.85 = 12.15.\n\nTip: Writing trailing zeros (12.40 instead of 12.4) keeps the columns aligned and prevents errors."},{"heading":"Multiplying & Dividing Decimals","body":"Multiply: ignore the decimal points, multiply the digits, then place the decimal so the answer has as many decimal places as the two factors combined.\n\nExample: 1.2 × 0.05. Multiply 12 × 5 = 60. Factors have 1 + 2 = 3 decimal places, so 0.060 = 0.06.\n\nDivide: move the decimal in the divisor to make it a whole number, move the dividend's decimal the same number of places, then divide.\n\nExample: 4.5 ÷ 0.9. Move both one place: 45 ÷ 9 = 5."},{"heading":"Equivalent & Simplified Fractions","body":"Expand (build an equivalent fraction): multiply top and bottom by the same number.\n\nExample: 3/4 = 9/12 (multiply both by 3). This is useful for getting a common denominator.\n\nSimplify (lowest terms): divide top and bottom by their greatest common factor.\n\nExample: 18/24. Both divide by 6: 18 ÷ 6 = 3 and 24 ÷ 6 = 4, so 18/24 = 3/4.\n\nTip: A fraction is fully simplified when the numerator and denominator share no common factor other than 1."},{"heading":"Mixed Numbers and Improper Fractions","body":"Mixed to improper: multiply the whole number by the denominator, add the numerator, keep the denominator.\n\nExample: 2 3/5 = (2 × 5 + 3)/5 = 13/5.\n\nImproper to mixed: divide numerator by denominator; the quotient is the whole number, the remainder is the new numerator.\n\nExample: 17/4. 17 ÷ 4 = 4 remainder 1, so 17/4 = 4 1/4."},{"heading":"Adding & Subtracting Fractions and Mixed Numbers","body":"Get a common denominator, add or subtract the numerators, keep the denominator, then simplify.\n\nExample: 1/3 + 1/4. LCD is 12: 4/12 + 3/12 = 7/12.\n\nMixed numbers: convert to like denominators, then combine whole and fraction parts.\n\nExample: 2 1/2 + 1 2/3 = 2 3/6 + 1 4/6 = 3 7/6. Since 7/6 = 1 1/6, the answer is 4 1/6.\n\nTip: When subtracting and the top fraction is smaller, borrow 1 from the whole number as a fraction first."},{"heading":"Multiplying & Dividing Fractions and Mixed Numbers","body":"Multiply: multiply straight across (top × top, bottom × bottom), then simplify. Convert any mixed numbers to improper fractions first.\n\nExample: 2/3 × 3/4 = 6/12 = 1/2.\n\nDivide: keep the first fraction, change ÷ to ×, and flip the second fraction (use its reciprocal).\n\nExample: 3/4 ÷ 2/3 = 3/4 × 3/2 = 9/8 = 1 1/8.\n\nMixed example: 1 1/2 × 2 = 3/2 × 2/1 = 6/2 = 3."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Convert Among Decimals, Fractions & Percents","slug":"convert-among-decimals-fractions-percents","summary":"Move freely among fractions, decimals, and percents, and compare values written in different forms.","blocks":[{"heading":"Fraction and Percent","body":"Fraction to percent: divide to get a decimal, then multiply by 100 (or multiply the fraction by 100 directly).\n\nExample: 3/4 = 3 ÷ 4 = 0.75 = 75%.\n\nPercent to fraction: write the percent over 100, then simplify.\n\nExample: 40% = 40/100 = 2/5 (divide top and bottom by 20).\n\nTip: Memorize a few anchors: 1/2 = 50%, 1/4 = 25%, 1/5 = 20%, 1/3 is about 33.3%."},{"heading":"Decimal and Percent","body":"Decimal to percent: move the decimal point two places to the right and add a % sign.\n\nExample: 0.6 = 60%. Also 0.075 = 7.5%.\n\nPercent to decimal: move the decimal point two places to the left and drop the % sign.\n\nExample: 85% = 0.85. Also 4% = 0.04.\n\nTip: Percent means per hundred, so the shift is always two places."},{"heading":"Fraction and Decimal","body":"Fraction to decimal: divide the numerator by the denominator.\n\nExample: 5/8 = 5 ÷ 8 = 0.625.\n\nDecimal to fraction: write the decimal over its place value (tenths, hundredths), then simplify.\n\nExample: 0.45 = 45/100 = 9/20 (divide top and bottom by 5)."},{"heading":"Comparing Across All Three Forms","body":"To compare a mix of fractions, decimals, and percents, convert them all to one form, usually decimals.\n\nExample: Order 0.7, 3/5, and 65% from least to greatest.\n- 3/5 = 0.60\n- 65% = 0.65\n- 0.7 = 0.70\nLeast to greatest: 0.60, 0.65, 0.70, which is 3/5 < 65% < 0.7.\n\nTip: Decimals are usually the easiest common form for lining values up and comparing place by place."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Solve Real World Problems Involving Percents","slug":"solve-real-world-problems-involving-percents","summary":"Find a percent of a whole, recover the whole from a part, read percents from tables, and handle increase, decrease, discount, and tax.","blocks":[{"heading":"Finding the Percent of a Whole","body":"Convert the percent to a decimal and multiply by the whole.\n\nExample: What is 20% of 80? 0.20 × 80 = 16.\n\nExample: A 250 mg dose; the patient gets 30% of it. 0.30 × 250 = 75 mg.\n\nTip: The word of usually signals multiplication."},{"heading":"Finding 100% from a Part","body":"When you know a part and what percent it represents, divide the part by the percent (as a decimal) to recover the whole.\n\nExample: 15 is 25% of what number? 15 ÷ 0.25 = 60.\n\nCheck: 25% of 60 = 0.25 × 60 = 15. Correct.\n\nTip: Set it up as part ÷ percent = whole. If the part is bigger than the percent suggests, the whole will be larger than the part."},{"heading":"Reading Percentages from Tables","body":"To get a percent from a table, divide the category amount by the total, then multiply by 100.\n\nExample: A table shows 45 patients out of 180 chose option A. Percent = 45 ÷ 180 = 0.25 = 25%.\n\nTip: Always confirm what the total is. Sometimes a table gives a grand total; other times you must add the rows yourself."},{"heading":"Percent Increase & Decrease","body":"Find the difference, then divide by the ORIGINAL amount, then convert to a percent.\n\nExample (increase): A price rises from 50 to 65. Change = 65 − 50 = 15. 15 ÷ 50 = 0.30 = 30% increase.\n\nExample (decrease): A count drops from 80 to 60. Change = 20. 20 ÷ 80 = 0.25 = 25% decrease.\n\nTip: Always divide by the original (starting) value, not the new value."},{"heading":"Discount & Tax","body":"Discount: multiply price by the discount percent to find the amount off, then subtract.\n\nExample: $80 item at 25% off. Discount = 0.25 × 80 = $20. Pay 80 − 20 = $60.\n\nTax: multiply price by the tax percent, then add.\n\nExample: $40 item with 8% tax. Tax = 0.08 × 40 = $3.20. Total = 40 + 3.20 = $43.20.\n\nTip: A 25% discount means you pay 75%, so you can also do 0.75 × 80 = $60 in one step."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Compare & Order Rational Numbers","slug":"compare-order-rational-numbers","summary":"Order fractions using common denominators and order mixed sets of negatives, decimals, and fractions together.","blocks":[{"heading":"Ordering Fractions","body":"Give the fractions a common denominator, then compare numerators.\n\nExample: Order 2/3, 3/5, 7/10 from least to greatest. LCD = 30.\n- 2/3 = 20/30\n- 3/5 = 18/30\n- 7/10 = 21/30\nCompare numerators: 18 < 20 < 21, so 3/5 < 2/3 < 7/10.\n\nTip: With the same denominator, the larger numerator is the larger fraction. You can also convert each to a decimal and compare that way."},{"heading":"Ordering Mixed Rational Numbers","body":"When the list mixes negatives, decimals, and fractions, convert everything to decimals, then order. For negatives, the number farther from zero is smaller (−2 < −1.5).\n\nExample: Order −1/2, 0.3, −1.5, 3/4, −2 from least to greatest.\n- Convert: −0.5, 0.3, −1.5, 0.75, −2\n- Order: −2 < −1.5 < −0.5 < 0.3 < 0.75\nFinal: −2, −1.5, −1/2, 0.3, 3/4.\n\nTip: On a number line, least to greatest goes left to right. All negatives come before zero, and all positives come after."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Solve Equations in One Variable","slug":"solve-equations-in-one-variable","summary":"Isolate the variable using inverse operations, from one-step equations up to multi-step equations with distribution and variables on both sides.","blocks":[{"heading":"One-Step & Two-Step Equations","body":"Undo operations using inverses to get the variable alone, doing the same thing to both sides.\n\nOne-step example: x + 7 = 12. Subtract 7 from both sides: x = 5. Also 3x = 21, divide both sides by 3: x = 7.\n\nTwo-step example: 2x + 5 = 17.\n- Subtract 5: 2x = 12\n- Divide by 2: x = 6\n\nTip: Undo addition or subtraction first, then multiplication or division (PEMDAS in reverse)."},{"heading":"Multi-Step Equations","body":"First distribute to clear parentheses and combine like terms, then move variables to one side and numbers to the other.\n\nDistribute example: 3(x − 2) = 15.\n- Distribute: 3x − 6 = 15\n- Add 6: 3x = 21\n- Divide by 3: x = 7\n\nVariables both sides example: 5x − 3 = 2x + 9.\n- Subtract 2x: 3x − 3 = 9\n- Add 3: 3x = 12\n- Divide by 3: x = 4\nCheck: 5(4) − 3 = 17 and 2(4) + 9 = 17. Both sides match.\n\nTip: Move the smaller variable term to avoid negatives, and always check by plugging your answer back in."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Apply Estimation Strategies and Rounding Rules to Real World Problems","slug":"apply-estimation-strategies-and-rounding-rules-to-real-world-problems","summary":"Round whole numbers and decimals correctly, and use estimation to check answers and solve word problems quickly.","blocks":[{"heading":"Rounding Whole Numbers & Decimals","body":"Find the place you are rounding to, then look at the digit just to its right. If that digit is 5 or more, round up; if 4 or less, round down (keep the digit). Drop or zero out everything after the rounding place.\n\nWhole number example: Round 4,687 to the nearest hundred. The hundreds digit is 6; the digit to its right is 8 (5 or more), so round up: 4,700.\n\nDecimal example: Round 3.6471 to the hundredths place. The hundredths digit is 4; the digit to its right is 7, so round up: 3.65.\n\nTip: Only the single digit immediately to the right decides the rounding. Ignore the digits beyond it."},{"heading":"Estimation in Word Problems","body":"Round the numbers to friendly values first, then compute, to get a quick approximate answer or to check a result for reasonableness.\n\nExample: About how much for 19 items at $4.85 each? Round to 20 × $5 = $100. The exact value, 19 × 4.85 = 92.15, is close to $100, so $100 is a sound estimate.\n\nTip: Estimation is great for catching big mistakes. If your calculated answer is far from your estimate, recheck your work."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Solve Real World Problems Involving Proportions, Ratios, and Rates of Change","slug":"solve-real-world-problems-involving-proportions-ratios-and-rates-of-change","summary":"Set up and solve ratio, rate, and proportion problems using cross-multiplication and unit rates.","blocks":[{"heading":"Setting Up Rates","body":"A rate compares two quantities with different units, written as a fraction. Keep the units consistent on top and bottom.\n\nExample: A car travels 150 miles in 3 hours. Rate = 150 miles / 3 hours = 50 miles per hour.\n\nTip: Label your units. Writing miles/hours keeps you from accidentally flipping the ratio."},{"heading":"Ratio, Rate & Proportion Word Problems","body":"A ratio compares parts. To split a total by a ratio, add the parts to find the number of shares, divide the total by that, then multiply.\n\nExample: Split 30 in a 3:2 ratio. Parts: 3 + 2 = 5 shares. 30 ÷ 5 = 6 per share. So 3 × 6 = 18 and 2 × 6 = 12. Check: 18 + 12 = 30.\n\nTip: The numbers in a ratio rarely add to the total directly; convert them to actual share sizes first."},{"heading":"Cross-Multiplying Proportions","body":"A proportion sets two ratios equal. Solve by cross-multiplying (multiply diagonally), then divide.\n\nExample: 4/6 = x/15. Cross-multiply: 6 × x = 4 × 15, so 6x = 60, then x = 10.\n\nExample: 3/4 = x/20. Cross-multiply: 4x = 60, so x = 15.\n\nTip: Keep matching units across from each other (miles with miles, hours with hours) when you build the proportion."},{"heading":"Unit Rates","body":"A unit rate tells you the amount per ONE unit. Divide to get a denominator of 1.\n\nExample: $5.40 for 6 items. Unit rate = 5.40 ÷ 6 = $0.90 per item.\n\nUnit rates make comparison shopping easy: the lower price per item is the better deal.\n\nExample: 240 miles on 8 gallons = 240 ÷ 8 = 30 miles per gallon."}]},
  {"section":"MATH","topic":"numbers-algebra","skill":"Translate Phrases and Sentences into Expressions, Equations, and Inequalities","slug":"translate-phrases-and-sentences-into-expressions-equations-and-inequalities","summary":"Turn words into algebra, simplify expressions, and solve inequalities, remembering to flip the sign when multiplying or dividing by a negative.","blocks":[{"heading":"Writing Expressions & Equations","body":"Translate key words: sum or more than means add, difference or less than means subtract, product or times means multiply, quotient means divide, is or equals means =.\n\nExpression examples:\n- 5 more than twice a number: 2n + 5\n- the quotient of x and 3: x/3\n\nEquation example: three less than a number is 12 becomes n − 3 = 12.\n\nTip: Less than reverses the order. Three less than a number is n − 3, not 3 − n."},{"heading":"Writing Inequalities","body":"Translate comparison phrases into inequality signs:\n- at least, no less than, minimum: ≥\n- at most, no more than, maximum: ≤\n- more than, greater than: >\n- less than, fewer than: <\n\nExample: A dose must be at least 10 mg becomes x ≥ 10. A wait time of no more than 30 minutes becomes t ≤ 30.\n\nTip: At least and at most include the boundary value, so they use ≥ and ≤."},{"heading":"Simplifying Expressions","body":"Combine like terms (terms with the same variable) and distribute when there are parentheses.\n\nCombine example: 3x + 5 − x + 2 = (3x − x) + (5 + 2) = 2x + 7.\n\nDistribute example: 2(3x − 4) = 2 × 3x − 2 × 4 = 6x − 8.\n\nTip: Only like terms combine. 2x and 7 cannot be added together because one has a variable and one does not."},{"heading":"Solving Inequalities (Flip the Sign)","body":"Solve inequalities like equations, but with one rule: when you multiply or divide both sides by a negative number, flip the inequality sign.\n\nExample: −2x < 6. Divide both sides by −2 and flip: x > −3.\n\nExample (no flip needed): 3x + 4 ≤ 19. Subtract 4: 3x ≤ 15. Divide by positive 3: x ≤ 5.\n\nTip: You only flip the sign for a negative multiply or divide, never for adding or subtracting."}]},
  {"section":"MATH","topic":"measurement-data","skill":"Interpret Relevant Information from Tables, Charts, and Graphs","slug":"interpret-relevant-information-from-tables-charts-and-graphs","summary":"Read values from bar graphs, line graphs, and tables, tell the independent from the dependent variable, and label a graph correctly.","blocks":[{"heading":"How to read each display","body":"Tables: find the row and the column the question names, then read the cell where they meet. Check the headers and units first.\n\nBar graphs: each bar's height (or length) is a quantity. Trace the top of the bar straight across to the value axis to read it.\n\nLine graphs: each point is a value at one input or time. Find the input on the horizontal axis, go straight up to the line, then straight left to read the value. Lines are best for showing change over time.\n\n- Read the title to know the topic\n- Read both axis labels and their units\n- Watch the scale: gridlines may count by 2, 5, 10, or 100, not by 1"},{"heading":"Independent vs dependent variable","body":"The independent variable is the input you control or that changes on its own (often time). It goes on the horizontal x-axis.\n\nThe dependent variable is the output that responds; its value depends on the independent variable. It goes on the vertical y-axis.\n\nQuick test: fill in \"___ depends on ___.\" The first blank is dependent, the second is independent.\n\n- Medication dose vs blood pressure: dose is independent (x), blood pressure is dependent (y)\n- Hours studied vs test score: hours is independent (x), score is dependent (y)"},{"heading":"Worked example: reading a line graph","body":"A clinic line graph shows patients seen each day: Mon 20, Tue 35, Wed 30, Thu 45, Fri 40. How many more patients were seen Thursday than Monday?\n\nRead Thursday's point (45) and Monday's point (20). Subtract: 45 - 20 = 25.\n\nAnswer: 25 more patients on Thursday."},{"heading":"Creating and labeling a graph","body":"To build a clear graph:\n\n- Give it a title stating what is shown\n- Put the independent variable on the x-axis, labeled with units\n- Put the dependent variable on the y-axis, labeled with units\n- Choose an even scale that fits all the data, with equal spacing between gridlines\n- Use bars for categories or counts; use a line for change over time\n\nTip: if a value lands between gridlines, estimate by how far between them it falls. Always answer using the graph's own scale, not by assuming each line equals 1."}]},
  {"section":"MATH","topic":"measurement-data","skill":"Evaluate Information in Tables, Charts, and Graphs Using Statistics","slug":"evaluate-information-in-tables-charts-and-graphs-using-statistics","summary":"Find mean, median, mode, and range from lists, tables, and frequency tables, and apply them in word problems.","blocks":[{"heading":"The four core measures","body":"Mean (average): add all values, then divide by how many there are. Mean = sum / count.\n\nMedian: the middle value once the data is sorted in order. With an even count, average the two middle values.\n\nMode: the value that appears most often. There can be no mode, one mode, or more than one.\n\nRange: largest value minus smallest value. Range = max - min. Range measures spread, not center."},{"heading":"Worked example: mean, median, mode, range","body":"Data: 4, 8, 6, 8, 9.\n\nMean: 4 + 8 + 6 + 8 + 9 = 35, then 35 / 5 = 7.\n\nMedian: sorted it is 4, 6, 8, 8, 9; the middle (3rd of 5) is 8.\n\nMode: 8 appears twice, more than any other, so mode = 8.\n\nRange: 9 - 4 = 5.\n\nEven-count median: for 4, 6, 8, 9 the two middle values are 6 and 8, so median = (6 + 8) / 2 = 7."},{"heading":"Mean from a table and a frequency table","body":"A frequency table lists each value with how many times it occurs. Do NOT just average the distinct values. Instead:\n\n- Multiply each value by its frequency\n- Add those products to get the total sum\n- Add the frequencies to get the total count\n- Divide: mean = total sum / total count\n\nExample: value 1 occurs 2 times, value 2 occurs 3 times, value 3 occurs 5 times.\nSum = (1x2) + (2x3) + (3x5) = 2 + 6 + 15 = 23.\nCount = 2 + 3 + 5 = 10.\nMean = 23 / 10 = 2.3."},{"heading":"Statistics word problems","body":"Find a missing value from a known mean by working backward: needed sum = mean x count.\n\nExample: a student scored 80, 90, and 85 and wants a mean of 88 over four tests. What 4th score is needed?\n\nNeeded total = 88 x 4 = 352. Current total = 80 + 90 + 85 = 255. Needed score = 352 - 255 = 97.\n\nTip: the mean is pulled toward outliers; the median is not. If one value is far from the rest, the median often describes the typical value better."}]},
  {"section":"MATH","topic":"measurement-data","skill":"Explain the Relationship Between Variables","slug":"explain-the-relationship-between-variables","summary":"Tell direct from inverse relationships, identify independent and dependent variables, read a line of best fit, and extrapolate beyond the data.","blocks":[{"heading":"Direct vs inverse relationships","body":"Direct (positive) relationship: as one variable increases, the other also increases. The trend rises from left to right (upward slope).\n\nInverse (negative) relationship: as one variable increases, the other decreases. The trend falls from left to right (downward slope).\n\n- Direct example: more hours worked, more pay earned\n- Inverse example: faster average speed, less travel time for a fixed distance\n- If points show no clear up or down pattern, there is little or no relationship"},{"heading":"Independent vs dependent variables","body":"The independent variable is the cause or input; it goes on the x-axis. The dependent variable is the effect or output; it changes in response and goes on the y-axis.\n\nUse the sentence \"the ___ depends on the ___\" to sort them. Whatever fills the first blank is dependent.\n\n- Plant growth depends on amount of sunlight: growth is dependent (y), sunlight is independent (x)"},{"heading":"Line of best fit and trends","body":"A scatter plot shows many points. A line of best fit is a single straight line drawn through the middle of the cloud to summarize the overall trend; about as many points fall above it as below.\n\n- Upward best-fit line = direct relationship\n- Downward best-fit line = inverse relationship\n- The closer the points hug the line, the stronger the relationship\n\nTo read a value, find the input on the x-axis, go up to the line, then across to the y-axis."},{"heading":"Extrapolating beyond the data","body":"Extrapolation means extending the trend line past the data you were given to estimate a value you did not measure. Interpolation is estimating between known points.\n\nExample: a best-fit line shows sales rising about 10 units each month, reaching 50 units in month 5. Extrapolate to month 7: continue the trend, 50 + 10 + 10 = 70 units.\n\nTip: extrapolation assumes the trend keeps going. Treat far-out predictions with caution, because real patterns can change outside the measured range."}]},
  {"section":"MATH","topic":"measurement-data","skill":"Calculate Geometric Quantities","slug":"calculate-geometric-quantities","summary":"Apply formulas for perimeter, area, circumference, surface area, volume, composite shapes, and scaling.","blocks":[{"heading":"Perimeter and area of basic shapes","body":"Perimeter is the distance around a shape (add all sides); area is the surface inside it (square units).\n\n- Rectangle: P = 2(L + W); A = L x W\n- Square (side s): P = 4s; A = s squared\n- Triangle: P = add all three sides; A = (1/2)bh, where b is the base and h is the height straight up from that base\n\nExample: a rectangle 8 cm by 3 cm has P = 2(8 + 3) = 22 cm and A = 8 x 3 = 24 cm squared.\nTriangle with base 10 and height 6: A = (1/2)(10)(6) = 30 square units."},{"heading":"Circles","body":"For a circle, r is the radius and the diameter d = 2r. Use pi about 3.14.\n\n- Circumference (distance around): C = 2(pi)r, or equally C = (pi)d\n- Area: A = (pi)r squared\n\nExample: a circle with radius 5 cm.\nC = 2 x 3.14 x 5 = 31.4 cm.\nA = 3.14 x 5 squared = 3.14 x 25 = 78.5 cm squared.\n\nTip: if you are given the diameter, halve it to get the radius before using A = (pi)r squared."},{"heading":"Irregular (composite) shapes","body":"A composite shape is made of basic shapes joined together. To find its area, break it into rectangles, triangles, and circle pieces, find each area, then add them (or subtract a cut-out).\n\nExample: an L-shape is a 6 by 4 rectangle with a 2 by 2 square removed from one corner.\nFull rectangle = 6 x 4 = 24. Removed square = 2 x 2 = 4. Area = 24 - 4 = 20 square units.\n\nFor the perimeter of an irregular shape, walk around the outline and add every outer edge. Tip: missing side lengths can often be found because opposite straight runs must match."},{"heading":"Surface area","body":"Surface area is the total area of all outer faces (square units).\n\n- Rectangular prism / box (length L, width W, height H): SA = 2(LW + LH + WH)\n- Cylinder (radius r, height h): SA = 2(pi)r squared + 2(pi)rh, the two circle ends plus the wrapped side\n\nBox example: L=4, W=3, H=2. SA = 2[(4x3) + (4x2) + (3x2)] = 2[12 + 8 + 6] = 2(26) = 52 square units.\nCylinder example: r=3, h=10. SA = 2(3.14)(9) + 2(3.14)(3)(10) = 56.52 + 188.4 = 244.92 square units."},{"heading":"Volume","body":"Volume is the space inside a solid (cubic units).\n\n- Box / rectangular prism: V = L x W x H\n- Cylinder: V = (pi)r squared x h\n\nBox example: L=4, W=3, H=2. V = 4 x 3 x 2 = 24 cubic units.\nCylinder example: r=3, h=10. V = 3.14 x 9 x 10 = 282.6 cubic units.\n\nTip: area uses square units (cm squared), volume uses cubic units (cm cubed). Match every dimension to the same unit before multiplying."},{"heading":"Scaling and similar figures","body":"A scale factor multiplies every length. Similar figures have the same shape with matching sides in equal ratio.\n\n- New length = old length x scale factor\n- If lengths scale by k, area scales by k squared and volume scales by k cubed\n- Map scale: set up a proportion, map distance / real distance = scale\n\nExample: a 4 cm by 6 cm rectangle scaled by factor 3 becomes 12 cm by 18 cm; its area grows by 3 squared = 9 times.\nMap example: scale is 1 in = 50 mi. A 3.5 in road = 3.5 x 50 = 175 mi.\nProportion example: if 2 cm represents 10 km, then 7 cm represents 7 x (10/2) = 35 km."}]},
  {"section":"MATH","topic":"measurement-data","skill":"Convert Within and Between Standard and Metric Units","slug":"convert-within-and-between-standard-and-metric-units","summary":"Convert within metric, within standard, between metric and standard for distance, liquid, and weight, and convert temperatures.","blocks":[{"heading":"Metric to metric","body":"Metric units share prefixes built on powers of 10, so you only move the decimal point.\n\n- 1 kilo = 1000 base (1 km = 1000 m, 1 kg = 1000 g, 1 kL = 1000 L)\n- 1 base = 1000 milli (1 m = 1000 mm, 1 g = 1000 mg, 1 L = 1000 mL)\n- 1 centi = 1/100 base (1 m = 100 cm)\n\nGoing to a smaller unit multiplies (more units); going to a larger unit divides.\nExample: 2.5 L = 2.5 x 1000 = 2500 mL. Example: 4500 g = 4500 / 1000 = 4.5 kg."},{"heading":"Standard to standard","body":"Memorize the common U.S. conversion factors.\n\n- Distance: 1 ft = 12 in; 1 yd = 3 ft; 1 mi = 5280 ft\n- Liquid: 1 gal = 4 qt; 1 qt = 2 pt; 1 pt = 2 cups; 1 cup = 8 fl oz\n- Weight: 1 lb = 16 oz; 1 ton = 2000 lb\n\nExample: 3 gal = 3 x 4 = 12 qt.\nExample: 48 in = 48 / 12 = 4 ft.\nExample: 5 lb = 5 x 16 = 80 oz."},{"heading":"Metric to standard (and back)","body":"Use these bridge factors. Multiply or divide based on which unit is larger.\n\n- Distance: 1 in = 2.54 cm; 1 mi about 1.6 km\n- Liquid: 1 L about 1.06 qt (roughly one quart); 1 gal about 3.79 L\n- Weight: 1 kg about 2.2 lb; 1 oz about 28.35 g\n\nExample: 10 in to cm = 10 x 2.54 = 25.4 cm.\nExample: 70 kg to lb = 70 x 2.2 = 154 lb.\nExample: 12.7 cm to in = 12.7 / 2.54 = 5 in.\nTip: write the factor as a fraction so the unit you do not want cancels."},{"heading":"Temperature: Celsius and Fahrenheit","body":"Use these two formulas:\n\n- Celsius to Fahrenheit: F = (9/5)C + 32\n- Fahrenheit to Celsius: C = (5/9)(F - 32)\n\nExample: convert 37 C (normal body temp). F = (9/5)(37) + 32 = 66.6 + 32 = 98.6 F.\nExample: convert 212 F (boiling water). C = (5/9)(212 - 32) = (5/9)(180) = 100 C.\n\nTip: for Fahrenheit to Celsius, subtract 32 FIRST, then multiply by 5/9. Doing the order wrong is the most common mistake."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Demonstrate Knowledge of the General Orientation of Human Anatomy","slug":"demonstrate-knowledge-of-the-general-orientation-of-human-anatomy","summary":"Anatomical position, directional terms, body planes, and cavities provide the shared map used to describe locations on the human body.","blocks":[{"heading":"Main job","body":"Give a standardized reference system so any body part can be located precisely. All terms assume anatomical position: standing erect, face forward, arms at sides, palms facing forward."},{"heading":"Key structures & facts","body":"Directional terms (in pairs):\n\n- Superior (above) vs inferior (below)\n- Anterior/ventral (front) vs posterior/dorsal (back)\n- Medial (toward midline) vs lateral (away from midline)\n- Proximal (closer to trunk/origin) vs distal (farther away)\n- Superficial (toward surface) vs deep (interior)\n\nBody planes:\n\n- Sagittal: divides into left and right (midsagittal = equal halves)\n- Frontal/coronal: divides into anterior and posterior\n- Transverse/horizontal: divides into superior and inferior\n\nBody cavities:\n\n- Dorsal cavity: cranial (brain) and vertebral/spinal (spinal cord)\n- Ventral cavity: thoracic (heart, lungs) and abdominopelvic; the diaphragm separates thoracic from abdominopelvic."},{"heading":"Tip","body":"Proximal/distal apply mainly to limbs; anterior/posterior describe the trunk. Remember the diaphragm is the muscular divider between the thoracic and abdominopelvic cavities."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Respiratory System","slug":"respiratory-system","summary":"The respiratory system moves air in and out and exchanges oxygen and carbon dioxide between air and blood.","blocks":[{"heading":"Main job","body":"Bring oxygen into the blood and remove carbon dioxide (gas exchange), and help regulate blood pH."},{"heading":"Key structures & facts","body":"- Air path: nose/nasal cavity > pharynx > larynx (voice box, contains epiglottis) > trachea > bronchi > bronchioles > alveoli\n- Alveoli are the tiny air sacs where gas exchange happens via diffusion with surrounding capillaries\n- Diaphragm is the main muscle of breathing; it contracts and flattens to inhale (increasing chest volume, lowering pressure)\n- Upper tract: nose, pharynx, larynx; lower tract: trachea, bronchi, lungs\n- Oxygen is carried on hemoglobin in red blood cells; CO2 is mostly carried as bicarbonate"},{"heading":"Tip","body":"Inhalation is active (diaphragm contracts); quiet exhalation is passive (diaphragm relaxes). The epiglottis covers the trachea during swallowing to keep food out of the airway."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Cardiovascular System","slug":"cardiovascular-system","summary":"The heart and blood vessels circulate blood to deliver oxygen and nutrients and remove wastes.","blocks":[{"heading":"Main job","body":"Pump and transport blood throughout the body, delivering oxygen and nutrients and carrying away carbon dioxide and wastes."},{"heading":"Blood-flow path","body":"Body (deoxygenated blood) > superior/inferior vena cava > right atrium > tricuspid valve > right ventricle > pulmonary (semilunar) valve > pulmonary arteries > lungs (pick up O2, drop off CO2) > pulmonary veins > left atrium > mitral/bicuspid valve > left ventricle > aortic (semilunar) valve > aorta > body.\n\nKey point: pulmonary arteries carry deoxygenated blood, pulmonary veins carry oxygenated blood (the exception to the usual rule)."},{"heading":"Key structures & facts","body":"- Four chambers: two atria (receive) on top, two ventricles (pump) on bottom\n- Left ventricle is the strongest chamber; it pumps to the whole body\n- Arteries carry blood away from the heart; veins carry blood toward the heart; capillaries are sites of exchange\n- Valves prevent backflow: tricuspid, pulmonary, mitral (bicuspid), aortic\n- The heartbeat starts at the SA node (natural pacemaker)"},{"heading":"Tip","body":"Arteries Away from the heart (both start with A). Most arteries carry oxygen-rich blood except the pulmonary arteries."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Gastrointestinal System","slug":"gastrointestinal-system","summary":"The GI tract breaks down food, absorbs nutrients, and eliminates solid waste.","blocks":[{"heading":"Main job","body":"Digest food mechanically and chemically, absorb nutrients into the blood, and remove undigested waste."},{"heading":"Key structures & facts","body":"- Path: mouth > esophagus > stomach > small intestine > large intestine > rectum > anus\n- Mouth: mechanical chewing plus salivary amylase begins carbohydrate digestion\n- Stomach: acid (HCl) and pepsin begin protein digestion\n- Small intestine (duodenum, jejunum, ileum): most digestion and nutrient absorption; villi increase surface area\n- Large intestine (colon): absorbs water and forms feces\n- Accessory organs: liver (makes bile), gallbladder (stores bile), pancreas (digestive enzymes plus bicarbonate)"},{"heading":"Tip","body":"Bile from the liver/gallbladder emulsifies fats but is not an enzyme. The small intestine is where most absorption occurs, not the stomach."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Neuromuscular System","slug":"neuromuscular-system","summary":"The nervous and muscular systems work together so the brain can sense the environment and produce movement.","blocks":[{"heading":"Main job","body":"Detect stimuli, process information, and trigger muscle contraction to create movement and maintain posture."},{"heading":"Key structures & facts","body":"- Nervous system divisions: central (brain and spinal cord) and peripheral (nerves); peripheral splits into somatic (voluntary) and autonomic (involuntary)\n- Autonomic has sympathetic (fight or flight) and parasympathetic (rest and digest) branches\n- Neuron is the basic cell; signals travel as electrical impulses and cross synapses via neurotransmitters (e.g., acetylcholine at the muscle)\n- Three muscle types: skeletal (voluntary, striated), cardiac (involuntary, striated, heart), smooth (involuntary, organs/vessels)\n- Muscles contract via the sliding of actin and myosin filaments and only pull, never push"},{"heading":"Tip","body":"Acetylcholine is the neurotransmitter released at the neuromuscular junction to start skeletal muscle contraction. Muscles work in antagonistic pairs (one contracts while the other relaxes)."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Reproductive System","slug":"reproductive-system","summary":"The reproductive system produces gametes and hormones and enables fertilization and, in females, pregnancy.","blocks":[{"heading":"Main job","body":"Produce sex cells (gametes), secrete sex hormones, and allow reproduction; the female system also supports fetal development."},{"heading":"Key structures & facts","body":"- Male: testes produce sperm and testosterone; sperm travels through epididymis > vas deferens > urethra; semen is supplied by the prostate and seminal vesicles\n- Female: ovaries produce eggs (ova) and estrogen/progesterone; egg travels through the fallopian tube where fertilization usually occurs; the uterus houses a developing fetus\n- Gametes are haploid (23 chromosomes); fertilization restores the diploid number (46)\n- The menstrual cycle is controlled by FSH and LH from the pituitary plus ovarian estrogen and progesterone\n- Ovulation is the release of an egg from the ovary, roughly mid cycle"},{"heading":"Tip","body":"Fertilization typically happens in the fallopian tube, not the uterus. Implantation of the embryo occurs in the uterine lining (endometrium)."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Integumentary System","slug":"integumentary-system","summary":"The skin, hair, and nails form a protective barrier and help regulate body temperature.","blocks":[{"heading":"Main job","body":"Protect the body from injury and pathogens, prevent water loss, regulate temperature, and provide sensation."},{"heading":"Key structures & facts","body":"- Three layers: epidermis (outer, no blood vessels, contains keratin and melanin), dermis (blood vessels, nerves, hair follicles, sweat and oil glands), hypodermis/subcutaneous (fat, insulation)\n- Melanin (made by melanocytes) gives color and protects against UV radiation\n- Sweat glands cool the body through evaporation; blood vessels dilate to release heat and constrict to conserve it\n- Skin produces vitamin D when exposed to sunlight\n- Accessory structures: hair, nails, sebaceous (oil) glands, sudoriferous (sweat) glands"},{"heading":"Tip","body":"The epidermis has no blood supply and gets nutrients by diffusion from the dermis. Skin is the body's largest organ and a key part of innate (first line) immunity."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Endocrine System","slug":"endocrine-system","summary":"Endocrine glands release hormones into the blood to regulate metabolism, growth, reproduction, and homeostasis.","blocks":[{"heading":"Main job","body":"Use hormones as chemical messengers to slowly and broadly regulate body processes; works with the nervous system to maintain homeostasis, often via negative feedback."},{"heading":"Gland to hormone pairs","body":"- Hypothalamus: releasing/inhibiting hormones; controls the pituitary\n- Pituitary (master gland): growth hormone, ADH (antidiuretic), oxytocin, FSH, LH, TSH, ACTH\n- Thyroid: thyroxine (T4/T3, sets metabolic rate) and calcitonin (lowers blood calcium)\n- Parathyroid: parathyroid hormone (PTH, raises blood calcium)\n- Adrenal glands: cortisol and aldosterone (cortex), epinephrine/adrenaline (medulla)\n- Pancreas: insulin (lowers blood sugar) and glucagon (raises blood sugar)\n- Ovaries: estrogen and progesterone; Testes: testosterone"},{"heading":"Tip","body":"Insulin lowers blood glucose, glucagon raises it; they are antagonists from the pancreas. Hormones travel in the bloodstream, so endocrine effects are slower but longer lasting than nerve signals."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Genitourinary System","slug":"genitourinary-system","summary":"The urinary organs filter blood to form urine, balancing water, electrolytes, and pH while removing wastes.","blocks":[{"heading":"Main job","body":"Filter waste (especially nitrogenous urea) from the blood, regulate water and electrolyte balance, control blood pressure and pH, and excrete urine."},{"heading":"Key structures & facts","body":"- Urine path: kidneys > ureters > bladder > urethra > out of body\n- The kidney's functional unit is the nephron, which filters blood and forms urine\n- Nephron steps: filtration (glomerulus), reabsorption (useful substances returned to blood), and secretion\n- Kidneys also help regulate blood pressure (renin) and red blood cell production (erythropoietin)\n- ADH from the pituitary increases water reabsorption, concentrating urine; aldosterone promotes sodium reabsorption"},{"heading":"Tip","body":"Ureters carry urine from kidneys to bladder; the single urethra carries urine out (don't mix them up). Healthy filtration keeps blood cells and large proteins in the bloodstream."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Immune System","slug":"immune-system","summary":"The immune system defends the body against pathogens using nonspecific and specific responses.","blocks":[{"heading":"Main job","body":"Recognize and destroy pathogens (bacteria, viruses, fungi) and abnormal cells, and build memory for faster future responses."},{"heading":"Key structures & facts","body":"- Innate (nonspecific) immunity: first line includes skin and mucous membranes; second line includes inflammation, fever, and phagocytes (e.g., macrophages, neutrophils)\n- Adaptive (specific) immunity: B cells make antibodies (humoral) and T cells attack infected cells (cell mediated)\n- White blood cells (leukocytes) are the main defenders; lymphocytes include B and T cells\n- Lymphatic organs: lymph nodes, spleen, thymus (T cells mature here), tonsils, bone marrow\n- Antibodies bind specific antigens; memory cells give long-term immunity and are the basis of vaccines"},{"heading":"Tip","body":"Skin and mucous membranes are the first line of defense and are nonspecific. Vaccines work by creating memory cells without causing the actual disease."}]},
  {"section":"SCIENCE","topic":"anatomy-physiology","skill":"Skeletal System","slug":"skeletal-system","summary":"Bones provide support, protect organs, enable movement, store minerals, and produce blood cells.","blocks":[{"heading":"Main job","body":"Form the body's framework: support and shape, protect organs, work with muscles for movement, store calcium and phosphorus, and produce blood cells in marrow."},{"heading":"Key structures & facts","body":"- The adult skeleton has 206 bones, divided into axial (skull, vertebral column, rib cage) and appendicular (limbs, shoulder, and pelvic girdles)\n- Red bone marrow produces blood cells (hematopoiesis); yellow marrow stores fat\n- Joints connect bones; cartilage cushions, ligaments connect bone to bone, tendons connect muscle to bone\n- Bone is living tissue that constantly remodels: osteoblasts build bone, osteoclasts break it down\n- Bones store about 99 percent of the body's calcium"},{"heading":"Tip","body":"Ligaments link bone to bone; tendons link muscle to bone. Remember osteoBlasts Build and osteoClasts Cut/clear away bone."}]},
  {"section":"SCIENCE","topic":"biology","skill":"Describe Cell Structure, Function, and Organization","slug":"describe-cell-structure-function-and-organization","summary":"Cells are the basic unit of life, built from organelles that each carry out specific jobs and organized into tissues, organs, and systems.","blocks":[{"heading":"What it is / key facts","body":"Prokaryotic cells (bacteria) lack a true nucleus and membrane-bound organelles; eukaryotic cells (plants, animals, fungi) have a nucleus and organelles.\n\nKey organelles and roles:\n- Nucleus: stores DNA and directs cell activities.\n- Ribosomes: build proteins (free or on rough ER).\n- Mitochondria: produce ATP through cellular respiration; the powerhouse of the cell.\n- Rough ER: studded with ribosomes, processes proteins; Smooth ER: makes lipids and detoxifies.\n- Golgi apparatus: packages and ships proteins and lipids.\n- Lysosomes: contain enzymes that digest waste and worn parts.\n- Cell (plasma) membrane: phospholipid bilayer that controls what enters and exits.\n\nOrganization runs cells to tissues to organs to organ systems to organism."},{"heading":"Example","body":"A muscle cell is packed with mitochondria because contracting muscle needs large amounts of ATP. Many muscle cells form muscle tissue, which builds organs like the heart, which works within the cardiovascular system."},{"heading":"Tip","body":"Link each organelle to a verb (mitochondria = make energy, ribosome = make protein, lysosome = digest). Plant cells add a cell wall, chloroplasts, and a large central vacuole that animal cells lack."}]},
  {"section":"SCIENCE","topic":"biology","skill":"Describe the Relationship Between Genetic Material and Protein Structure","slug":"describe-the-relationship-between-genetic-material-and-protein-structure","summary":"DNA carries the code that is transcribed into RNA and translated into proteins, so the DNA base sequence ultimately determines a protein's amino acid sequence.","blocks":[{"heading":"What it is / key facts","body":"The central dogma is DNA to RNA to protein.\n\n- DNA bases: adenine (A), thymine (T), cytosine (C), guanine (G); pairing is A-T and C-G.\n- RNA uses uracil (U) instead of thymine, so DNA A pairs with RNA U.\n- Transcription (in the nucleus): DNA is copied into messenger RNA (mRNA).\n- Translation (at the ribosome): mRNA is read in three-base codons; each codon specifies one amino acid, and transfer RNA (tRNA) brings the matching amino acid.\n- Amino acids link into a chain that folds into a functional protein. A change in the DNA sequence (mutation) can change the amino acid and alter or break the protein."},{"heading":"Example","body":"DNA template strand T-A-C reads to mRNA codon A-U-G, which is the start codon coding for methionine. A single base change such as sickle cell disease (one amino acid swap in hemoglobin) shows how one altered DNA base reshapes a protein and its function."},{"heading":"Tip","body":"Remember DNA stays in the nucleus while the message (mRNA) travels out to the ribosome. Three bases equal one codon equal one amino acid."}]},
  {"section":"SCIENCE","topic":"biology","skill":"Apply Concepts Underlying Mendel's Laws of Inheritance","slug":"apply-concepts-underlying-mendel-s-laws-of-inheritance","summary":"Mendel's laws explain how alleles separate and combine, and a Punnett square predicts the genotype and phenotype ratios of offspring.","blocks":[{"heading":"What it is / key facts","body":"- Gene: a unit of heredity; alleles are alternate versions (dominant shown as a capital letter, recessive lowercase).\n- Homozygous = two identical alleles (BB or bb); heterozygous = two different alleles (Bb).\n- Genotype is the allele pair; phenotype is the visible trait.\n- Law of Segregation: the two alleles separate so each gamete carries only one.\n- Law of Independent Assortment: alleles for different traits sort independently.\n- A dominant allele masks a recessive one, so a recessive trait appears only when both alleles are recessive."},{"heading":"Example","body":"Cross two heterozygous brown-eyed parents (Bb x Bb), where B (brown) is dominant over b (blue).\n\nPunnett square gives: BB, Bb, Bb, bb.\n\n- Genotype ratio: 1 BB : 2 Bb : 1 bb.\n- Phenotype ratio: 3 brown : 1 blue (about 75 percent brown, 25 percent blue)."},{"heading":"Tip","body":"Put one parent's alleles across the top and the other's down the side, then fill each box. The classic monohybrid heterozygous cross always gives a 3:1 phenotype ratio and a 1:2:1 genotype ratio."}]},
  {"section":"SCIENCE","topic":"biology","skill":"Describe the Structure and Function of the Basic Macromolecules in a Biological System","slug":"describe-the-structure-and-function-of-the-basic-macromolecules-in-a-biological-system","summary":"The four biological macromolecules (carbohydrates, lipids, proteins, and nucleic acids) are built from specific monomers and each serves distinct roles in the body.","blocks":[{"heading":"What it is / key facts","body":"- Carbohydrates: monomer is monosaccharide (glucose); main quick energy source; includes starch and glycogen for storage.\n- Lipids (fats): built from glycerol plus fatty acids; not true polymers; store energy long term, form cell membranes (phospholipids), and make steroid hormones.\n- Proteins: monomer is amino acid (20 types); functions include enzymes, structure (collagen), transport (hemoglobin), and defense (antibodies).\n- Nucleic acids: monomer is nucleotide; DNA and RNA store and carry genetic information.\n\nMonomers join into polymers by dehydration synthesis (removing water) and are broken apart by hydrolysis (adding water)."},{"heading":"Example","body":"After a meal, dietary starch (a carbohydrate polymer) is digested by hydrolysis into glucose monomers; cells then use glucose in mitochondria to make ATP. Extra glucose is stored as glycogen in the liver."},{"heading":"Tip","body":"Match each macromolecule to its monomer: carbs to monosaccharides, proteins to amino acids, nucleic acids to nucleotides; lipids are the exception (glycerol and fatty acids, not a repeating monomer). Nitrogen is a clue for proteins and nucleic acids."}]},
  {"section":"SCIENCE","topic":"biology","skill":"Describe the Role of Microorganisms in Disease","slug":"describe-the-role-of-microorganisms-in-disease","summary":"Pathogenic microorganisms such as bacteria, viruses, fungi, and protozoa cause infectious disease, and knowing the pathogen type guides treatment.","blocks":[{"heading":"What it is / key facts","body":"- Bacteria: single-celled prokaryotes that can reproduce on their own; cause strep throat, tuberculosis, and many UTIs; treated with antibiotics.\n- Viruses: not cells; they must hijack a host cell to replicate; cause influenza, the common cold, COVID-19, and HIV; antibiotics do not work, antivirals or vaccines are used.\n- Fungi: cause infections like ringworm, athlete's foot, and yeast infections; treated with antifungals.\n- Protozoa: single-celled eukaryotes such as the parasite causing malaria.\n\nNot all microbes are harmful; normal flora (such as gut bacteria) help digestion and crowd out pathogens. A pathogen is any disease-causing microbe."},{"heading":"Example","body":"A sore throat from Streptococcus bacteria responds to antibiotics, but the flu (a virus) does not, because antibiotics target bacterial structures viruses lack. This is why prescribing antibiotics for a viral cold is ineffective and fuels antibiotic resistance."},{"heading":"Tip","body":"Remember antibiotics treat bacteria, not viruses. Sort pathogens by type first (bacterium, virus, fungus, protozoan) because the type determines the correct treatment."}]},
  {"section":"SCIENCE","topic":"chemistry","skill":"Recognize Basic Atomic Structure","slug":"recognize-basic-atomic-structure","summary":"Atoms are built from protons, neutrons, and electrons, and their counts define an element's identity, mass, and charge.","blocks":[{"heading":"Key facts","body":"An atom has a dense central nucleus surrounded by electrons.\n\n- Protons: positive (+1) charge, found in the nucleus\n- Neutrons: no charge (neutral), found in the nucleus\n- Electrons: negative (-1) charge, orbit outside the nucleus\n\nAtomic number = number of protons; it identifies the element and never changes for that element.\n\nMass number = protons + neutrons (electrons are too light to count).\n\nA neutral atom has equal protons and electrons. Gaining electrons makes a negative ion (anion); losing electrons makes a positive ion (cation). Isotopes are atoms of the same element with different neutron counts."},{"heading":"Example","body":"Carbon has atomic number 6, so it always has 6 protons. Carbon-12 has mass number 12, so neutrons = 12 - 6 = 6. A neutral carbon atom also has 6 electrons.\n\nIf a sodium atom (11 protons) loses 1 electron, it has 10 electrons and a +1 charge, written Na+."},{"heading":"Tip","body":"Memorize the charge cues: prOtons are pOsitive, neutrons are neutral, and electrons are the leftover negatives. To find neutrons, subtract the atomic number from the mass number."}]},
  {"section":"SCIENCE","topic":"chemistry","skill":"Explain Physical Properties and Changes of Matter","slug":"explain-physical-properties-and-changes-of-matter","summary":"Physical changes alter form or state without creating a new substance, while physical properties can be observed without changing identity.","blocks":[{"heading":"Key facts","body":"A physical property can be measured or observed without changing the substance's chemical identity.\n\n- Examples: color, density, melting point, boiling point, state, solubility\n\nA physical change alters appearance or state but the substance stays chemically the same and is often reversible.\n\n- Examples: melting, freezing, boiling, condensing, dissolving, cutting, crushing\n\nStates of matter: solid (fixed shape and volume), liquid (fixed volume, takes container shape), gas (fills its container). Changing state is physical because the molecules stay the same. Contrast this with a chemical change, which produces a new substance."},{"heading":"Example","body":"Ice melting into liquid water and then boiling into steam is all physical change; it is still H2O the whole time, just in different states.\n\nDissolving salt in water is physical, the salt can be recovered by evaporating the water."},{"heading":"Tip","body":"Ask: Is it still the same stuff? If yes, the change is physical. State changes and dissolving are classic physical changes, even though they look dramatic."}]},
  {"section":"SCIENCE","topic":"chemistry","skill":"Describe Chemical Reactions","slug":"describe-chemical-reactions","summary":"Chemical reactions rearrange atoms to form new substances, and balanced equations show that matter is conserved.","blocks":[{"heading":"Key facts","body":"In a chemical reaction, reactants become products with new chemical properties. Signs include color change, gas or bubbles, a precipitate, or heat/light released.\n\nThe law of conservation of mass means atoms are not created or destroyed, so equations must be balanced (same number of each atom on both sides). Use coefficients, never change subscripts.\n\nCommon reaction types:\n- Synthesis: A + B yields AB\n- Decomposition: AB yields A + B\n- Single replacement: A + BC yields AC + B\n- Double replacement: AB + CD yields AD + CB\n- Combustion: fuel + O2 yields CO2 + H2O"},{"heading":"Example","body":"Balancing the formation of water: 2 H2 + O2 yields 2 H2O. Left side has 4 H and 2 O; right side has 4 H and 2 O, so it is balanced.\n\nIron rusting (a chemical change) combines iron and oxygen to form a new compound, iron oxide."},{"heading":"Tip","body":"Balance by adjusting coefficients (the big numbers in front), not subscripts, because subscripts define the substance. Count atoms element by element and tackle oxygen and hydrogen last."}]},
  {"section":"SCIENCE","topic":"chemistry","skill":"Understand Properties of Solutions","slug":"understand-properties-of-solutions","summary":"A solution is a uniform mixture of a solute dissolved in a solvent, and the pH scale measures how acidic or basic that solution is.","blocks":[{"heading":"Key facts","body":"A solution is a homogeneous mixture.\n\n- Solute: the substance being dissolved (smaller amount), like salt\n- Solvent: the substance doing the dissolving (larger amount), like water; water is the universal solvent\n\nConcentration describes how much solute is present; more solute makes a solution more concentrated, more solvent makes it more dilute.\n\nThe pH scale runs 0 to 14:\n- pH below 7 = acidic (more hydrogen ions, H+)\n- pH 7 = neutral (pure water)\n- pH above 7 = basic/alkaline\n\nThe scale is logarithmic, so each whole number is a tenfold change in acidity."},{"heading":"Example","body":"In salt water, salt is the solute and water is the solvent.\n\nStomach acid is around pH 2 (strongly acidic), pure water is pH 7 (neutral), and household bleach is around pH 12 (basic). Human blood is tightly regulated near pH 7.4, slightly basic."},{"heading":"Tip","body":"Remember solute is the smaller amount that gets dissolved; solvent is the larger amount that does the dissolving. For pH, lower numbers mean more acidic and 7 is the neutral middle."}]},
  {"section":"SCIENCE","topic":"scientific-reasoning","skill":"Use Basic Scientific Measurements and Measurement Tools","slug":"use-basic-scientific-measurements-and-measurement-tools","summary":"Match each tool to the quantity it measures and report the value in the correct unit.","blocks":[{"heading":"What it is","body":"Every physical quantity has a matching tool and a standard unit. Pairing the three correctly is the core of measurement.\n\n- Length: meter stick or ruler, measured in meters (m), centimeters (cm), or millimeters (mm).\n- Volume of a liquid: graduated cylinder, measured in milliliters (mL) or liters (L).\n- Mass: balance, measured in grams (g) or kilograms (kg).\n- Temperature: thermometer, measured in degrees Celsius (C) or Kelvin (K).\n- Time: stopwatch, measured in seconds (s).\n\nNote that mass (amount of matter, from a balance) is not the same as weight (pull of gravity, from a scale or spring)."},{"heading":"How the TEAS tests it","body":"Questions ask which tool measures a given quantity, or which unit fits a measurement.\n\n- They mix in a wrong unit so a number looks reasonable but is mislabeled, such as reporting liquid volume in grams.\n- They test reading a graduated cylinder at the bottom of the curved surface (the meniscus) at eye level.\n- They may ask you to convert within metric prefixes, where 1 km = 1000 m and 1 L = 1000 mL."},{"heading":"Example","body":"A nurse needs to record how much liquid medication is in a dosing cup. Which tool and unit fit?\n\n- Volume is measured with a graduated cylinder or marked cup, reported in milliliters (mL).\n- A balance and grams would be wrong because those measure mass, not volume.\n\nIf the cup reads to the 7 mL line at the meniscus, you record 7 mL."},{"heading":"Tip","body":"Build a quick mental table: quantity, then tool, then unit. If a choice swaps the unit (volume in grams) or the tool (mass with a ruler), eliminate it.\n\nRead liquid volume at the bottom of the meniscus with your eye level to the line to avoid a skewed reading."}]},
  {"section":"SCIENCE","topic":"scientific-reasoning","skill":"Apply Logic and Evidence to Scientific Explanations","slug":"apply-logic-and-evidence-to-scientific-explanations","summary":"Judge whether evidence actually supports a claim, and separate correlation from causation.","blocks":[{"heading":"What it is","body":"A strong scientific explanation is backed by evidence and sound logic, not just a pattern you noticed.\n\n- Correlation means two things change together.\n- Causation means one thing actually makes the other happen.\n- Two variables can move together because a third hidden factor drives both, or by pure coincidence.\n\nOnly a controlled experiment, not a single observation, can support a cause-and-effect claim."},{"heading":"How the TEAS tests it","body":"Questions give a finding and ask which conclusion is justified.\n\n- The trap answer states causation (X causes Y) when the data only show correlation (X and Y rise together).\n- They ask you to spot a confounding variable that could explain the link.\n- They reward the cautious wording, such as \"is associated with\" instead of \"causes,\" when the study only observed a pattern."},{"heading":"Example","body":"A survey finds that towns selling more sunscreen also report more cases of heat exhaustion. Can we conclude sunscreen causes heat exhaustion?\n\n- No. Both rise because of a third factor: hot, sunny weather drives both sunscreen sales and heat exhaustion.\n- This is correlation explained by a confounding variable, not causation.\n\nThe logical conclusion is that the two are associated, with weather as the likely common cause."},{"heading":"Tip","body":"When an answer choice says \"causes,\" ask whether the study actually changed one variable and controlled the rest. If it only observed, downgrade to \"is linked to.\"\n\nWatch for a hidden third variable; it is the most common reason a correlation is not causation."}]},
  {"section":"SCIENCE","topic":"scientific-reasoning","skill":"Predict Relationships Among Events, Objects, and Processes","slug":"predict-relationships-among-events-objects-and-processes","summary":"Use an observed trend or rule to predict what happens next when one factor changes.","blocks":[{"heading":"What it is","body":"Predicting means using a known relationship to say what one variable will do when another changes.\n\n- Direct relationship: as one goes up, the other goes up (more exercise, higher heart rate).\n- Inverse relationship: as one goes up, the other goes down (more altitude, lower oxygen).\n\nReading the direction of the trend in a data table or graph lets you extend it to a new value."},{"heading":"How the TEAS tests it","body":"Questions give a table, graph, or stated rule and ask what will happen next.\n\n- They ask you to extend a trend beyond the last data point.\n- They test whether you can tell a direct relationship from an inverse one.\n- A trap reverses the direction, predicting an increase where the trend clearly falls."},{"heading":"Example","body":"A table shows that as water temperature rises, the time for a sugar cube to dissolve drops: 10 C takes 60 s, 20 C takes 40 s, 30 C takes 25 s. Predict the dissolve time at 40 C.\n\n- The relationship is inverse: higher temperature means shorter time.\n- The trend keeps falling, so 40 C should take less than 25 s.\n\nA prediction near 15 s fits the downward pattern; predicting more than 25 s would contradict it."},{"heading":"Tip","body":"First label the relationship as direct or inverse, then push the trend one step further in the same direction.\n\nIf a choice breaks the established direction (says \"increase\" when every step decreased), eliminate it."}]},
  {"section":"SCIENCE","topic":"scientific-reasoning","skill":"Apply the Scientific Method to Interpret a Scientific Investigation","slug":"apply-the-scientific-method-to-interpret-a-scientific-investigation","summary":"Identify the variable types and the hypothesis, and draw only conclusions the data support.","blocks":[{"heading":"What it is","body":"The scientific method tests a hypothesis by changing one factor and watching the result while holding everything else steady.\n\n- Independent variable: the one factor the researcher changes on purpose.\n- Dependent variable: the outcome that is measured in response.\n- Controlled variables: the factors kept the same so they do not interfere.\n- Control group: the untreated baseline used for comparison.\n\nA valid conclusion stays within what the data actually show."},{"heading":"How the TEAS tests it","body":"Questions describe a study and ask you to label its parts or judge its conclusion.\n\n- Identify the independent vs dependent variable from the setup.\n- Spot which variables had to be controlled and why a control group matters.\n- Choose the conclusion supported by the results, and reject ones that overreach beyond the data or ignore the control."},{"heading":"Example","body":"A student gives three identical plants 0 mL, 50 mL, and 100 mL of water per day, keeps light, soil, and pot size the same, and measures growth in cm after two weeks.\n\n- Independent variable: amount of water (what is changed).\n- Dependent variable: plant growth in cm (what is measured).\n- Controlled variables: light, soil, pot size (kept the same).\n\nIf the 100 mL plant grew most, a valid conclusion is that more water increased growth in this range, not that water is the only thing plants need."},{"heading":"Tip","body":"Find the independent variable by asking what the researcher deliberately changed; the dependent variable is whatever they measured as a result.\n\nReject any conclusion that claims more than the data show or that ignores keeping other variables controlled."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Identifying Correct Spelling","slug":"identifying-correct-spelling","summary":"Correct spelling follows standard patterns, including tricky rules for adding endings and commonly confused words.","blocks":[{"heading":"Rule","body":"Learn the patterns behind common spelling errors instead of memorizing every word.\n\n- Use \"i before e except after c\" for many words: believe, receive.\n- When adding an ending to a word that ends in a silent e, drop the e before a vowel ending: hope becomes hoping.\n- Double the final consonant before a vowel ending when a one-syllable word ends in one vowel plus one consonant: stop becomes stopped."},{"heading":"Examples","body":"Correct: The nurse will administer the medication and document the dosage.\n\nIncorrect: The nurse will administar the medecation and documment the dosege."},{"heading":"Tip","body":"Watch homophones that sound alike but mean different things, such as their, there, and they're, or patient and patience. Read the sentence aloud to confirm the meaning matches the spelling."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Correct Use of End Punctuation","slug":"correct-use-of-end-punctuation","summary":"End a sentence with a period, question mark, or exclamation point based on its purpose.","blocks":[{"heading":"Rule","body":"Match the end mark to the type of sentence.\n\n- Use a period for a statement or a mild command.\n- Use a question mark for a direct question.\n- Use an exclamation point for strong emotion or urgency, and use it sparingly in formal writing."},{"heading":"Examples","body":"Correct: Did you check the patient's blood pressure? Record it now.\n\nIncorrect: Did you check the patient's blood pressure. Record it now?"},{"heading":"Tip","body":"An indirect question is a statement and takes a period, not a question mark. Write \"She asked whether the results were ready.\" not \"She asked whether the results were ready?\""}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Using Commas with Introductory Words","slug":"using-commas-with-introductory-words","summary":"Place a comma after an introductory word, phrase, or clause that comes before the main part of the sentence.","blocks":[{"heading":"Rule","body":"Set off the introductory element with a comma so the reader knows where the main idea begins.\n\n- Use a comma after introductory words like However, Therefore, and Yes.\n- Use a comma after an introductory phrase such as \"After the shift\" or \"In the morning.\"\n- Use a comma after an introductory dependent clause such as \"Because she was tired.\""},{"heading":"Examples","body":"Correct: After the long shift, the nurse charted her notes.\n\nIncorrect: After the long shift the nurse charted her notes."},{"heading":"Tip","body":"A very short introductory phrase of one or two words sometimes does not require a comma, but adding one is rarely wrong and improves clarity."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Using Commas to Join Clauses Together","slug":"using-commas-to-join-clauses-together","summary":"Use a comma plus a coordinating conjunction to join two independent clauses.","blocks":[{"heading":"Rule","body":"Join two complete sentences with a comma and a coordinating conjunction (FANBOYS: for, and, nor, but, or, yet, so).\n\n- The comma goes before the conjunction, not after it.\n- Do not use a comma alone between two independent clauses, which creates a comma splice.\n- Do not add a comma when the conjunction joins only two verbs or two subjects."},{"heading":"Examples","body":"Correct: The patient rested, and the swelling decreased.\n\nIncorrect: The patient rested, the swelling decreased."},{"heading":"Tip","body":"Test each side of the conjunction. If both sides can stand alone as a sentence, you need the comma plus conjunction. If one side cannot stand alone, leave the comma out."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Using Commas with Nonessential Clauses","slug":"using-commas-with-nonessential-clauses","summary":"Surround nonessential information with commas; do not set off information the sentence needs to identify its subject.","blocks":[{"heading":"Rule","body":"Use commas around a clause that adds extra detail but is not needed to identify what it describes.\n\n- A nonessential clause can be removed without changing the basic meaning, so set it off with commas.\n- An essential clause limits the meaning and is needed, so use no commas.\n- The word which usually signals nonessential detail; that usually signals essential detail."},{"heading":"Examples","body":"Correct: Dr. Lee, who trained in Boston, leads the unit.\n\nIncorrect: The nurse, who charted the vitals, must sign the form."},{"heading":"Tip","body":"Read the sentence without the clause. If it still points to the same specific person or thing, the clause is nonessential and needs commas on both sides."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Commas Separating Adjectives","slug":"commas-separating-adjectives","summary":"Use a comma between coordinate adjectives that independently describe the same noun.","blocks":[{"heading":"Rule","body":"Separate adjectives with a comma when each one modifies the noun equally.\n\n- Adjectives are coordinate if you can swap their order or insert the word and between them.\n- Use no comma when the adjectives are not equal, such as when the last adjective forms a unit with the noun.\n- Never place a comma between the final adjective and the noun."},{"heading":"Examples","body":"Correct: She was a calm, focused nurse during the emergency.\n\nIncorrect: She wore bright, blue scrubs to the clinic."},{"heading":"Tip","body":"Try inserting and between the adjectives. \"Calm and focused\" sounds right, so use a comma. \"Bright and blue scrubs\" changes the meaning, so leave the comma out."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Using Commas in a Series","slug":"using-commas-in-a-series","summary":"Use commas to separate three or more items in a list, including before the final conjunction.","blocks":[{"heading":"Rule","body":"Place a comma after each item in a series of three or more.\n\n- Include the comma before and or or at the end of the list; this is the serial or Oxford comma.\n- The serial comma prevents confusion about which items are grouped together.\n- The series can be words, phrases, or short clauses."},{"heading":"Examples","body":"Correct: The cart held gloves, gauze, tape, and scissors.\n\nIncorrect: The cart held gloves gauze tape and scissors."},{"heading":"Tip","body":"On the TEAS, keep the comma before the final and. It is the standard choice and avoids cases where two items run together as if they were one."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Correctly Punctuating Quotations","slug":"correctly-punctuating-quotations","summary":"Place quotation marks around exact spoken or written words and put periods and commas inside the marks.","blocks":[{"heading":"Rule","body":"Use quotation marks to enclose a direct quotation of someone's exact words.\n\n- Put commas and periods inside the closing quotation mark.\n- Use a comma to separate the quotation from a speaker tag, such as \"She said.\"\n- Capitalize the first word of a quoted sentence."},{"heading":"Examples","body":"Correct: The patient said, \"I feel much better today.\"\n\nIncorrect: The patient said \"I feel much better today\"."},{"heading":"Tip","body":"An indirect quotation that reports an idea without exact words takes no quotation marks. Write \"The patient said she felt better\" with no quotation marks."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Correct Use of Colons","slug":"correct-use-of-colons","summary":"Use a colon after a complete sentence to introduce a list, explanation, or example.","blocks":[{"heading":"Rule","body":"A colon points forward to what follows, and the words before it must form a complete sentence.\n\n- Use a colon to introduce a list, a quotation, or an explanation.\n- Do not place a colon directly after a verb or a preposition.\n- The first word after the colon is usually lowercase unless it begins a complete sentence or is a proper noun."},{"heading":"Examples","body":"Correct: Bring three items: a stethoscope, a pen, and a notebook.\n\nIncorrect: Bring: a stethoscope, a pen, and a notebook."},{"heading":"Tip","body":"Cover everything after the colon and read what is left. If it is a full sentence, the colon is correct. If it is not, remove the colon."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Correct Use of Parentheses","slug":"correct-use-of-parentheses","summary":"Use parentheses to enclose extra information that could be removed without breaking the sentence.","blocks":[{"heading":"Rule","body":"Parentheses set off nonessential details, clarifications, or asides.\n\n- The sentence must read correctly when the parenthetical material is removed.\n- Place end punctuation outside the closing parenthesis when the parentheses fall inside a larger sentence.\n- Do not put a comma directly before an opening parenthesis."},{"heading":"Examples","body":"Correct: The medication (a common antibiotic) was prescribed for ten days.\n\nIncorrect: The medication, (a common antibiotic) was prescribed for ten days."},{"heading":"Tip","body":"Use parentheses sparingly. If the detail is important to the main point, work it into the sentence directly rather than tucking it inside parentheses."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Types of Sentences","slug":"types-of-sentences","summary":"Sentences are classified by purpose as declarative, interrogative, imperative, or exclamatory.","blocks":[{"heading":"Rule","body":"Identify a sentence by what it does and the end mark it takes.\n\n- Declarative sentences make a statement and end with a period.\n- Interrogative sentences ask a question and end with a question mark.\n- Imperative sentences give a command or request and usually end with a period.\n- Exclamatory sentences express strong feeling and end with an exclamation point."},{"heading":"Examples","body":"Correct: Take a deep breath. (imperative) Are you in pain? (interrogative)\n\nIncorrect: Take a deep breath? (a command marked as a question)"},{"heading":"Tip","body":"An imperative sentence often has an unstated subject of you. \"Check the chart\" means \"You check the chart,\" so it is still a complete sentence."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Identifying Correct Sentence Structure","slug":"identifying-correct-sentence-structure","summary":"A complete sentence needs a subject and a verb and must avoid fragments, run-ons, and comma splices.","blocks":[{"heading":"Rule","body":"Build complete sentences and join clauses correctly.\n\n- A fragment is missing a subject, a verb, or a complete thought.\n- A run-on jams two independent clauses together with no punctuation.\n- A comma splice joins two independent clauses with only a comma; fix it with a period, a semicolon, or a comma plus a conjunction."},{"heading":"Examples","body":"Correct: The shift ended; the nurse went home.\n\nIncorrect: The shift ended the nurse went home."},{"heading":"Tip","body":"When two independent clauses are closely related, a semicolon links them cleanly without a conjunction. Make sure a full sentence sits on each side of it."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Subject-Verb Agreement","slug":"subject-verb-agreement","summary":"A verb must agree in number with its subject, even when words come between them.","blocks":[{"heading":"Rule","body":"Match a singular subject with a singular verb and a plural subject with a plural verb.\n\n- Ignore phrases that fall between the subject and verb when deciding the verb form.\n- Most indefinite pronouns like each, everyone, and either are singular.\n- Subjects joined by and are usually plural; with subjects joined by or, the verb agrees with the nearer subject."},{"heading":"Examples","body":"Correct: The box of supplies is on the counter.\n\nIncorrect: The box of supplies are on the counter."},{"heading":"Tip","body":"Find the true subject by crossing out any phrase that starts with of, in, or with. The verb agrees with the noun that remains, not with the noun nearest the verb."}]},
  {"section":"ENGLISH","topic":"conventions","skill":"Misplaced and Dangling Modifiers","slug":"misplaced-and-dangling-modifiers","summary":"Place modifiers next to the word they describe so the sentence states what you mean.","blocks":[{"heading":"Rule","body":"Keep each modifier close to the word it modifies.\n\n- A misplaced modifier sits too far from its target and seems to describe the wrong word.\n- A dangling modifier describes a word that is not actually in the sentence.\n- Fix a dangling modifier by naming the correct subject right after the opening phrase."},{"heading":"Examples","body":"Correct: Walking into the room, the nurse greeted the patient.\n\nIncorrect: Walking into the room, the chart was on the bed."},{"heading":"Tip","body":"When a sentence opens with an -ing or -ed phrase, the noun right after the comma must be the one doing that action. Ask who performed the action and put that subject first."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Identifying Genre","slug":"identifying-genre","summary":"Genre is the category a piece of writing belongs to, based on its form, content, and purpose.","blocks":[{"heading":"What it is","body":"Genre is the type or category of a text. Common genres include fiction, nonfiction, poetry, drama, biography, and reference writing.\n\nGenre is shaped by purpose and structure:\n\n- Fiction tells an invented story.\n- Nonfiction shares facts and real information.\n- Poetry uses rhythm, line breaks, and figurative language.\n- Drama is written to be performed, using dialogue and stage directions."},{"heading":"How the TEAS tests it","body":"You read a short passage and choose its genre, or you match a description to the correct genre.\n\nLook for signals: stage directions and character names point to drama, line breaks and rhyme point to poetry, and dated personal entries point to a journal or memoir."},{"heading":"Example","body":"\"Nurse Patel checked the monitor, then turned to the new resident. 'Watch the heart rate,' she said, 'it is climbing too fast.'\"\n\nThe invented characters and dialogue advancing a story make this fiction, not a factual report."},{"heading":"Tip","body":"Ask two quick questions: Is it real or invented, and what form is it in? Those two answers usually pin down the genre fast."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Matching Sentences to Types of Writing","slug":"matching-sentences-to-types-of-writing","summary":"The four main writing types are narrative, expository, persuasive, and technical, each with its own purpose.","blocks":[{"heading":"What it is","body":"Writing is grouped by its main purpose:\n\n- Narrative tells a story or recounts events.\n- Expository explains or informs without taking sides.\n- Persuasive argues a position and tries to convince.\n- Technical gives precise instructions or specialized procedures."},{"heading":"How the TEAS tests it","body":"You read one sentence and identify which type of writing it fits.\n\nMatch by purpose: a story moment is narrative, a neutral explanation is expository, an opinion with a call to act is persuasive, and a step or specification is technical."},{"heading":"Example","body":"\"Insert the catheter slowly to the marked line, then secure it with tape.\" This is technical writing because it gives an exact procedure.\n\nCompare: \"Every nurse should get the flu vaccine to protect patients.\" That sentence is persuasive."},{"heading":"Tip","body":"Decide the writer's goal first: to tell, to explain, to convince, or to instruct. The goal names the type."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Identifying Intended Audience","slug":"identifying-intended-audience","summary":"The intended audience is the specific group a writer expects to read the text.","blocks":[{"heading":"What it is","body":"The intended audience is who the writing is meant for. Word choice, detail level, and tone all reveal it.\n\nA piece for experts uses specialized terms, while a piece for the general public explains those terms or avoids them."},{"heading":"How the TEAS tests it","body":"You read a passage and choose the most likely audience, such as children, patients, or medical professionals.\n\nLook at vocabulary and assumed knowledge. Heavy jargon signals a specialist audience; simple, defined terms signal a general or beginner audience."},{"heading":"Example","body":"\"This handout explains, in plain words, what your blood pressure numbers mean and when to call your doctor.\"\n\nThe plain wording and caregiving framing show the audience is patients, not clinicians."},{"heading":"Tip","body":"Ask who would need this information and already understand the words used. The level of the language points straight to the reader."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Identifying Appropriate Language for Intended Audience/Tone","slug":"identifying-appropriate-language-for-intended-audience-tone","summary":"Effective writing matches its formality, word choice, and tone to its audience and purpose.","blocks":[{"heading":"What it is","body":"Tone is the writer's attitude, and language should fit both the tone and the reader.\n\n- Formal language suits professional or academic settings and avoids slang.\n- Informal language is casual and conversational.\n- Tone can be serious, encouraging, neutral, or urgent depending on the goal."},{"heading":"How the TEAS tests it","body":"You pick the sentence whose language best fits a given audience or tone, or you spot a phrase that does not match.\n\nWatch for mismatches, such as slang in a formal report or stiff jargon in a friendly patient note."},{"heading":"Example","body":"For a clinical chart, \"The patient reports moderate abdominal pain\" fits the formal tone.\n\nFor a get-well card to a friend, \"Hope you feel better soon\" fits the warm, informal tone. Swapping them would feel wrong."},{"heading":"Tip","body":"Picture the setting. If it is professional, choose precise formal wording; if it is personal, a warmer everyday voice usually fits better."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Stages of the Writing Process","slug":"stages-of-the-writing-process","summary":"The writing process moves through five stages: prewriting, drafting, revising, editing, and publishing.","blocks":[{"heading":"What it is","body":"The five stages, in order:\n\n- Prewriting: brainstorm ideas, gather information, and plan or outline.\n- Drafting: write the first version, getting ideas down.\n- Revising: improve content, organization, and clarity of ideas.\n- Editing: fix grammar, spelling, punctuation, and mechanics.\n- Publishing: share the finished, polished piece."},{"heading":"How the TEAS tests it","body":"You identify which stage a described action belongs to, or put the stages in order.\n\nKeep the key difference clear: revising changes ideas and structure, while editing fixes surface errors like commas and spelling."},{"heading":"Example","body":"A student lists every fact she knows about diabetes and groups them before writing. That is prewriting.\n\nLater she rereads her draft and moves a paragraph so the argument flows better. That is revising."},{"heading":"Tip","body":"Remember the order with planning first and polishing last. If the action changes meaning it is revising; if it corrects errors it is editing."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Parts of a Paragraph","slug":"parts-of-a-paragraph","summary":"A strong paragraph has a topic sentence, supporting details, and a concluding sentence.","blocks":[{"heading":"What it is","body":"A well-built paragraph has three main parts:\n\n- Topic sentence: states the main idea.\n- Supporting details: facts, examples, and explanations that develop that idea.\n- Concluding sentence: wraps up or restates the point.\n\nTransitions connect the sentences smoothly."},{"heading":"How the TEAS tests it","body":"You identify the topic sentence, pick the best supporting detail, or choose a fitting concluding sentence.\n\nThe topic sentence is usually broadest; supporting sentences are more specific and all relate back to it."},{"heading":"Example","body":"Topic sentence: \"Handwashing is the simplest way to prevent infection.\" Supporting detail: \"Scrubbing for twenty seconds removes most germs.\" Concluding sentence: \"A few seconds at the sink protects every patient.\""},{"heading":"Tip","body":"Find the sentence that the others explain or prove. That broad sentence is the topic sentence, and everything else should support it."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Identifying Unrelated Sentences","slug":"identifying-unrelated-sentences","summary":"An unrelated sentence breaks a paragraph's unity by not supporting the topic sentence.","blocks":[{"heading":"What it is","body":"Every sentence in a paragraph should support the main idea. A sentence that drifts to a different topic or adds an off-point detail breaks unity and should be removed.\n\nThis off-topic sentence is sometimes called an irrelevant or distracting detail."},{"heading":"How the TEAS tests it","body":"You read a short paragraph and choose the sentence that does not belong.\n\nFirst nail down the main idea from the topic sentence, then test each sentence: if one does not develop that idea, it is the unrelated one."},{"heading":"Example","body":"\"Regular exercise strengthens the heart. It lowers blood pressure and improves circulation. My cousin just bought new running shoes. It also helps control weight.\"\n\nThe shoes sentence is unrelated; it does not explain how exercise helps the heart."},{"heading":"Tip","body":"Reread the topic sentence, then ask of each line, does this prove or explain the main idea? If the answer is no, that sentence does not belong."}]},
  {"section":"ENGLISH","topic":"knowledge-language","skill":"Using Grammar to Enhance Clarity in Writing","slug":"using-grammar-to-enhance-clarity-in-writing","summary":"Clear grammar, word choice, and sentence structure make writing precise and easy to understand.","blocks":[{"heading":"What it is","body":"Grammar choices shape clarity. Strong writing uses:\n\n- Precise, concrete word choice over vague terms.\n- Clear pronoun references so readers know who or what is meant.\n- Correctly placed modifiers and parallel structure.\n- Concise wording that cuts needless repetition."},{"heading":"How the TEAS tests it","body":"You choose the clearest, most effective version of a sentence, or fix a confusing one.\n\nWatch for vague pronouns, misplaced modifiers, wordiness, and shifts that muddy the meaning. The clearest, most precise option is usually correct."},{"heading":"Example","body":"Unclear: \"After charting the medications, the cart was left in the hall.\" This dangling modifier suggests the cart did the charting.\n\nClear: \"After charting the medications, the nurse left the cart in the hall.\""},{"heading":"Tip","body":"Read the sentence and ask who is doing what. If the actor is missing or a pronoun is unclear, pick the version that names it directly."}]},
  {"section":"ENGLISH","topic":"vocabulary","skill":"Using Prefixes to Determine Word Meaning","slug":"using-prefixes-to-determine-word-meaning","summary":"A prefix is added to the front of a root word and shifts its meaning, often signaling negation, direction, or amount.","blocks":[{"heading":"What it is","body":"A prefix is a word part attached before a root or base word. Learning a handful of common prefixes lets you decode unfamiliar terms, which is useful for both the English section and clinical vocabulary.\n\nSplit the word into parts, define the prefix, then add it to the root meaning to estimate the whole."},{"heading":"Reference list","body":"- un- : not, opposite of (unable)\n\n- in- / im- : not (invisible, impossible)\n\n- dis- : not, away, apart (disagree)\n\n- non- : not (nonfatal)\n\n- mal- : bad, badly (malnutrition)\n\n- hyper- : over, above, excessive (hypertension)\n\n- hypo- : under, below, deficient (hypothermia)\n\n- pre- : before (preoperative)\n\n- post- : after (postpartum)\n\n- anti- : against (antibiotic)\n\n- sub- : under, below (subcutaneous)\n\n- re- : again, back (rehydrate)"},{"heading":"Tip","body":"Watch the pairs that look alike but mean opposites, like hyper- (too much) versus hypo- (too little). Mixing them up flips the meaning of a medical term completely."}]},
  {"section":"ENGLISH","topic":"vocabulary","skill":"Using Suffixes to Determine Word Meaning","slug":"using-suffixes-to-determine-word-meaning","summary":"A suffix is added to the end of a word and usually marks its part of speech or, in medical terms, a condition or procedure.","blocks":[{"heading":"What it is","body":"A suffix is a word part attached after a root. Suffixes often tell you whether a word is a noun, verb, or adjective, and in clinical language they name conditions, processes, and procedures.\n\nIdentify the suffix to predict the word's role and general meaning, then combine it with the root."},{"heading":"Reference list","body":"- -able / -ible : capable of, able to be (treatable, reversible)\n\n- -less : without (painless)\n\n- -ful : full of (harmful)\n\n- -ous : full of, having (nervous)\n\n- -ist : one who practices (pharmacist)\n\n- -tion / -sion : act or state of (digestion, tension)\n\n- -ity : state or quality of (acidity)\n\n- -ize : to make, to cause (sterilize)\n\n- -itis : inflammation (arthritis)\n\n- -ology : study of (cardiology)\n\n- -emia : blood condition (anemia)\n\n- -pathy : disease, disorder (neuropathy)"},{"heading":"Tip","body":"Suffixes are reliable clues to part of speech: -tion and -ity usually signal a noun, -ize a verb, and -ous or -able an adjective. That alone can help you pick the grammatically correct answer."}]},
  {"section":"ENGLISH","topic":"vocabulary","skill":"Using Common Root Words to Determine Word Meaning","slug":"using-common-root-words-to-determine-word-meaning","summary":"The root carries the core meaning of a word, so knowing common Greek and Latin roots unlocks many related terms at once.","blocks":[{"heading":"What it is","body":"A root is the central part of a word that holds its main meaning; prefixes and suffixes build around it. Most academic and medical vocabulary comes from Greek and Latin roots.\n\nFind the root, recall its meaning, and use it as the anchor for understanding the full word."},{"heading":"Reference list","body":"- spect : to look, to see (inspect)\n\n- dict : to say, to speak (predict)\n\n- port : to carry (transport)\n\n- scrib / script : to write (prescribe)\n\n- struct : to build (construct)\n\n- cardi : heart (cardiac)\n\n- derm : skin (dermatology)\n\n- gastr : stomach (gastric)\n\n- neur : nerve (neuron)\n\n- bio : life (biology)\n\n- audi : to hear (auditory)\n\n- vis : to see (vision)"},{"heading":"Tip","body":"One root often appears in a whole family of words. If you know cardi means heart, you can reason through cardiac, cardiology, and cardiovascular even if you have never seen them before."}]},
  {"section":"ENGLISH","topic":"vocabulary","skill":"Use Context Clues to Determine Word Meaning","slug":"use-context-clues-to-determine-word-meaning","summary":"Context clues are hints in the surrounding sentence that help you figure out an unfamiliar word without a dictionary.","blocks":[{"heading":"What it is","body":"When you meet a word you do not know, the words around it often define or hint at its meaning. Reading the full sentence and nearby sentences for these signals is faster and more reliable than guessing from the word alone."},{"heading":"Reference list","body":"The four common clue types:\n\n- Definition: the meaning is stated directly. Example: The patient had tachycardia, a faster than normal heart rate.\n\n- Synonym: a nearby word means the same thing. Example: The wound was sterile, completely clean and free of germs.\n\n- Antonym: a contrast word signals the opposite. Example: Unlike her usually placid roommate, Mia was restless and anxious.\n\n- Example: instances clarify the word. Example: Many analgesics, such as ibuprofen and acetaminophen, relieve mild pain."},{"heading":"Tip","body":"Look for signal words. Phrases like which means or that is point to definitions, while however, unlike, and but point to antonyms. Such as and including introduce examples."}]},
];

export function getSkillLesson(section: string, topic: string, slug: string): SkillLesson | undefined {
  return SKILL_LESSONS.find((c) => c.section === section && c.topic === topic && c.slug === slug);
}
